/* ═══════════════════════════════════════════════════
   SCATTER PLOT — Fwd P/E vs EPS Growth (all watchlist stocks)
═══════════════════════════════════════════════════ */
function renderScatter(activeStock) {
  var canvas = document.getElementById('scatterCanvas');
  if (!canvas) return;
  var dpr = window.devicePixelRatio || 1;
  var rect = canvas.getBoundingClientRect();
  var W = rect.width || canvas.offsetWidth || 400;
  var H = 220;
  canvas.width  = W * dpr;
  canvas.height = H * dpr;
  canvas.style.width  = W + 'px';
  canvas.style.height = H + 'px';
  var ctx = canvas.getContext('2d');
  ctx.scale(dpr, dpr);

  // Gather data points (exclude outliers: P/E > 60 or growth <= 0 or missing)
  var pts = [];
  Object.values(STOCKS).forEach(function(s) {
    if (!s.fwdEPS || s.fwdEPS <= 0) return;
    var pe = s.livePrice / s.fwdEPS;
    if (pe <= 0 || pe > 60) return;
    // Derive fwd EPS growth from historicalTable fcagr on EPS row, or skip
    var growth = null;
    if (s.historicalTable && s.historicalTable.rows) {
      var epsRow = s.historicalTable.rows.find(function(r) { return r.label && r.label.toLowerCase().includes('eps'); });
      if (epsRow && epsRow.fcagr && epsRow.fcagr !== '—') {
        growth = parseFloat(epsRow.fcagr);
      }
    }
    // Fallback: compute from EPS fwd trajectory vs live EPS
    if (growth == null || isNaN(growth) || growth <= 0) return;
    var mos = s.targetPrice > 0 ? Math.max(0, (s.targetPrice - s.livePrice) / s.targetPrice * 100) : 10;
    pts.push({ ticker: s.ticker, pe: pe, growth: growth, mos: mos, rating: s.rating, isActive: s.ticker === activeStock.ticker });
  });

  if (pts.length === 0) {
    ctx.fillStyle = 'rgba(138,155,191,0.4)';
    ctx.font = '11px DM Sans,sans-serif';
    ctx.fillText('No data available (stocks need historicalTable with EPS CAGR)', 20, H/2);
    return;
  }

  // Axis ranges
  var allPE     = pts.map(function(p) { return p.pe; });
  var allGrowth = pts.map(function(p) { return p.growth; });
  var minPE = Math.max(0, Math.min.apply(null, allPE) - 2);
  var maxPE = Math.min(60, Math.max.apply(null, allPE) + 5);
  var minGr = Math.max(0, Math.min.apply(null, allGrowth) - 2);
  var maxGr = Math.max.apply(null, allGrowth) + 5;

  var pad = { l:42, r:15, t:14, b:36 };
  var pw = W - pad.l - pad.r;
  var ph = H - pad.t - pad.b;

  function xPos(g)  { return pad.l + (g - minGr) / (maxGr - minGr) * pw; }
  function yPos(pe) { return pad.t + ph - (pe - minPE) / (maxPE - minPE) * ph; }

  // Draw grid
  ctx.strokeStyle = 'rgba(31,39,54,0.8)';
  ctx.lineWidth = 1;
  // Horizontal grid lines
  var peStep = (maxPE - minPE) > 30 ? 10 : 5;
  for (var pe2 = Math.ceil(minPE / peStep) * peStep; pe2 <= maxPE; pe2 += peStep) {
    var y2 = yPos(pe2);
    ctx.beginPath(); ctx.moveTo(pad.l, y2); ctx.lineTo(W - pad.r, y2);
    ctx.stroke();
    ctx.fillStyle = 'rgba(74,88,117,0.9)';
    ctx.font = '8px DM Mono,monospace';
    ctx.textAlign = 'right';
    ctx.fillText(pe2 + 'x', pad.l - 4, y2 + 3);
  }
  // Vertical grid lines
  var grStep = (maxGr - minGr) > 40 ? 10 : 5;
  for (var gr2 = Math.ceil(minGr / grStep) * grStep; gr2 <= maxGr; gr2 += grStep) {
    var x2 = xPos(gr2);
    ctx.beginPath(); ctx.moveTo(x2, pad.t); ctx.lineTo(x2, H - pad.b);
    ctx.stroke();
    ctx.fillStyle = 'rgba(74,88,117,0.9)';
    ctx.font = '8px DM Mono,monospace';
    ctx.textAlign = 'center';
    ctx.fillText(gr2 + '%', x2, H - pad.b + 10);
  }

  // Fair value line (PEG = 1 → P/E = growth)
  ctx.save();
  ctx.strokeStyle = 'rgba(96,165,250,0.25)';
  ctx.setLineDash([4, 4]);
  ctx.lineWidth = 1;
  ctx.beginPath();
  var startGr = Math.max(minGr, 1);
  ctx.moveTo(xPos(startGr), yPos(startGr));
  ctx.lineTo(xPos(Math.min(maxGr, maxPE)), yPos(Math.min(maxPE, maxGr)));
  ctx.stroke();
  ctx.restore();

  // Axis labels
  ctx.fillStyle = 'rgba(74,88,117,0.9)';
  ctx.font = '9px DM Sans,sans-serif';
  ctx.textAlign = 'center';
  ctx.fillText('Fwd EPS CAGR (%)', pad.l + pw/2, H - 2);
  ctx.save();
  ctx.translate(11, pad.t + ph/2);
  ctx.rotate(-Math.PI/2);
  ctx.fillText('Fwd P/E', 0, 0);
  ctx.restore();

  // PEG=1 label
  ctx.fillStyle = 'rgba(96,165,250,0.5)';
  ctx.font = '8px DM Mono,monospace';
  ctx.textAlign = 'left';
  var pgx = xPos(Math.min(maxGr - 1, 30));
  var pgy = yPos(Math.min(maxPE - 1, 30));
  if (pgx < W - pad.r - 30 && pgy > pad.t + 10) ctx.fillText('PEG=1', pgx + 3, pgy - 3);

  // Draw bubbles
  var ratingColors = { BUY:'rgba(52,211,153,', HOLD:'rgba(251,191,36,', WAIT:'rgba(167,139,250,', SELL:'rgba(248,113,113,' };
  pts.sort(function(a, b) { return a.isActive ? 1 : b.isActive ? -1 : 0; }); // active on top

  pts.forEach(function(p) {
    var x = xPos(p.growth);
    var y = yPos(p.pe);
    var r = Math.max(5, Math.min(14, p.mos / 4));
    var col = (ratingColors[p.rating] || 'rgba(138,155,191,') ;
    
    // Bubble
    ctx.beginPath();
    ctx.arc(x, y, r, 0, Math.PI * 2);
    ctx.fillStyle = p.isActive ? col + '0.85)' : col + '0.35)';
    ctx.fill();
    ctx.strokeStyle = p.isActive ? col + '1)' : col + '0.6)';
    ctx.lineWidth = p.isActive ? 2 : 1;
    ctx.stroke();

    // Ticker label
    ctx.fillStyle = p.isActive ? '#e6ecf8' : 'rgba(138,155,191,0.85)';
    ctx.font = (p.isActive ? 'bold ' : '') + '8px DM Mono,monospace';
    ctx.textAlign = 'center';
    var labelY = y - r - 3;
    if (labelY < pad.t + 8) labelY = y + r + 9;
    ctx.fillText(p.ticker, x, labelY);
  });
}

/* ═══════════════════════════════════════════════════
   WATCHLIST PRIORITY SYSTEM
   Stored in localStorage so it persists across reloads.
   Priority values: 'watchlist' (default) | 'bought' | 'backburner'
═══════════════════════════════════════════════════ */
const PRIORITY_KEY = 'wl_priorities_v1';

function loadPriorities() {
  try { return JSON.parse(localStorage.getItem(PRIORITY_KEY) || '{}'); } catch(e) { return {}; }
}

function savePriorities(map) {
  try { localStorage.setItem(PRIORITY_KEY, JSON.stringify(map)); } catch(e) {}
}

function getTickerPriority(ticker) {
  const map = loadPriorities();
  return map[ticker] || 'watchlist';
}

function setTickerPriority(ticker, val) {
  const map = loadPriorities();
  if (val === 'watchlist') { delete map[ticker]; } else { map[ticker] = val; }
  savePriorities(map);
}

function applyPriorityFilter() { applyAllFilters(); }

function _applyPriorityFilter_orig() {
  const filter = document.getElementById('priorityFilter').value;
  const rows = document.querySelectorAll('#watchlistBody tr');
  let visible = 0;
  rows.forEach(function(tr) {
    const ticker = tr.getAttribute('data-ticker');
    const prio = getTickerPriority(ticker);
    const show = filter === 'all' || prio === filter;
    tr.style.display = show ? '' : 'none';
    if (show) visible++;
  });
  const totalCount = rows.length;
  const countEl = document.getElementById('priorityCount');
  if (countEl) {
    countEl.textContent = filter === 'all' ? (totalCount + ' stocks') : (visible + ' of ' + totalCount + ' stocks');
  }
}

function buildPriorityCell(ticker) {
  const prio = getTickerPriority(ticker);
  const labels = { bought: 'Bought', watchlist: 'Watchlist', backburner: 'Backburner' };
  return '<select class="prio-pill ' + prio + '" onchange="changePriority(\'' + ticker + '\', this)" onclick="event.stopPropagation()" title="Set list priority">' +
    '<option value="watchlist"' + (prio==='watchlist'?' selected':'') + '>Watchlist</option>' +
    '<option value="bought"' + (prio==='bought'?' selected':'') + '>Bought</option>' +
    '<option value="backburner"' + (prio==='backburner'?' selected':'') + '>Backburner</option>' +
    '</select>';
}

function changePriority(ticker, selectEl) {
  const val = selectEl.value;
  setTickerPriority(ticker, val);
  // Update styling of the select element
  selectEl.className = 'prio-pill ' + val;
  // Re-apply filter if a specific filter is active
  const filter = document.getElementById('priorityFilter').value;
  if (filter !== 'all') applyPriorityFilter();
}

/* ═══════════════════════════════════════════════════
   WATCHLIST TABLE RENDER
═══════════════════════════════════════════════════ */
let currentStock = null;

// safeId: converts a ticker into a valid CSS id/selector-safe string
// e.g. "1024.HK" → "t1024_HK" so querySelector('#t1024_HK-d1-content') works
function safeId(ticker) {
  return 't' + String(ticker).replace(/[^a-zA-Z0-9]/g, '_');
}

// ── sort state ──────────────────────────────────
let _sortCol = -1, _sortAsc = true;

function sortTable(col) {
  if (_sortCol === col) { _sortAsc = !_sortAsc; }
  else { _sortCol = col; _sortAsc = true; }
  document.querySelectorAll('#theadRow th .sort-icon').forEach((el, i) => {
    el.textContent = i === col ? (_sortAsc ? '↑' : '↓') : '⇅';
  });
  renderTable();
}

function fmtPrice(v) {
  if (v === null || v === undefined || isNaN(v)) return '—';
  return v < 10 ? v.toFixed(2) : Math.round(v).toString();
}

function renderTable() {
  const tbody = document.getElementById('watchlistBody');
  let stocks = Object.values(STOCKS);
  document.getElementById('stockCount').textContent = stocks.length;

  if (_sortCol >= 0) {
    stocks.sort((a, b) => {
      const uA = ((a.targetPrice - a.livePrice) / a.livePrice * 100);
      const uB = ((b.targetPrice - b.livePrice) / b.livePrice * 100);
      const eA = ((a.livePrice - a.entryPrice) / a.entryPrice * 100);
      const eB = ((b.livePrice - b.entryPrice) / b.entryPrice * 100);
      const rA = ((a.livePrice - a.reportPrice) / a.reportPrice * 100);
      const rB = ((b.livePrice - b.reportPrice) / b.reportPrice * 100);
      let va, vb;
      switch (_sortCol) {
        case 0:  va=a.ticker;            vb=b.ticker;            break;
        case 1:  va=a.name;              vb=b.name;              break;
        case 2:  va=a.rating;            vb=b.rating;            break;
        case 3:  va=a.sqScore;           vb=b.sqScore;           break;
        case 4:  va=a.livePrice;         vb=b.livePrice;         break;
        case 5:  va=(a.livePxChange||0); vb=(b.livePxChange||0); break;
        case 6: {
          const w52pct = s => (!s.week52High||!s.week52Low||s.week52High<=s.week52Low) ? -1 : (s.livePrice-s.week52Low)/(s.week52High-s.week52Low)*100;
          va=w52pct(a); vb=w52pct(b); break;
        }
        case 7:  va=a.reportPrice;       vb=b.reportPrice;       break;
        case 8:  va=rA;                  vb=rB;                  break;
        case 9:  va=a.targetPrice;       vb=b.targetPrice;       break;
        case 10: va=uA;                  vb=uB;                  break;
        case 11: va=a.entryPrice;        vb=b.entryPrice;        break;
        case 12: va=eA;                  vb=eB;                  break;
        case 13: va=a.sector;            vb=b.sector;            break;
        default: va=0; vb=0;
      }
      if (typeof va === 'string') return _sortAsc ? va.localeCompare(vb) : vb.localeCompare(va);
      return _sortAsc ? va - vb : vb - va;
    });
  }

  let buys = 0, totalUpside = 0;
  tbody.innerHTML = '';

  stocks.forEach(s => {
    const upside     = ((s.targetPrice - s.livePrice) / s.livePrice * 100);
    const reportDiff = ((s.livePrice - s.reportPrice) / s.reportPrice * 100);
    const entryDiff  = ((s.livePrice - s.entryPrice)  / s.entryPrice  * 100);
    if (s.rating === 'BUY') buys++;
    totalUpside += upside;

    const entryFlagHtml = buildEntryFlag(entryDiff);

    const tr = document.createElement('tr');
    tr.className = s.rating;
    tr.setAttribute('data-ticker', s.ticker);
    tr.onclick = () => openCard(s.ticker);
    tr.innerHTML =
      '<td><span class="ticker-cell">' + s.ticker + '</span></td>' +
      '<td><span class="name-cell">' + s.name + '</span></td>' +
      '<td><span class="rating-badge ' + s.rating + '">' + s.rating + '</span></td>' +
      '<td>' + buildPriorityCell(s.ticker) + '</td>' +
      '<td><span class="sq-pill"><span class="sq-dot" style="background:' + sqColor(s.sqScore) + '"></span>' + s.sqScore + '/' + s.dislocationScore + '</span></td>' +
      '<td id="tbl-live-'   + s.ticker + '"><span class="price-mono">$' + fmtPrice(s.livePrice) + '</span></td>' +
      '<td id="tbl-pxchg-'  + s.ticker + '">' + buildPxChg(s) + '</td>' +
      '<td id="tbl-w52-'    + s.ticker + '">' + buildW52Bar(s) + '</td>' +
      '<td><span class="price-mono" style="color:var(--text3)">$' + fmtPrice(s.reportPrice) + '</span></td>' +
      '<td id="tbl-rdiff-'  + s.ticker + '">' + buildDeltaPct(reportDiff, 25) + '</td>' +
      '<td><span class="ref-mono">$' + fmtPrice(s.targetPrice) + '</span></td>' +
      '<td id="tbl-upside-' + s.ticker + '">' + buildDeltaPct(upside, 50) + '</td>' +
      '<td><span class="price-mono" style="color:var(--cyan)">$' + fmtPrice(s.entryPrice) + '</span></td>' +
      '<td id="tbl-entryflag-' + s.ticker + '">' + entryFlagHtml + '</td>' +
      '<td><span class="sector-chip">' + s.sector + '</span></td>' +
      '<td><span class="open-btn" onclick="event.stopPropagation();openCard(\'' + s.ticker + '\')">Open \u2192</span></td>';
    tbody.appendChild(tr);
  });

  document.getElementById('statBuys').textContent = buys;
  document.getElementById('statAvgUpside').textContent = (totalUpside / stocks.length).toFixed(1) + '%';
}

// Gradient colour: red at -10%+, amber at -3%, neutral at 0, lime at +5%, green at +15%+
function gradientPctColor(v, maxMag) {
  if (v === null || v === undefined || isNaN(v)) return 'var(--text3)';
  const mag = maxMag || 15;
  const clamped = Math.max(-mag, Math.min(mag, v));
  if (v === 0) return 'var(--text3)';
  if (v > 0) {
    // 0 → +mag: text3 → lime → green
    const t = Math.min(clamped / mag, 1);
    const r = Math.round(53  + (52  - 53)  * t);
    const g = Math.round(162 + (211 - 162) * t);
    const b = Math.round(55  + (153 - 55)  * t);
    return `rgb(${r},${g},${b})`;
  } else {
    // 0 → -mag: text3 → amber → red
    const t = Math.min(-clamped / mag, 1);
    if (t < 0.4) {
      // amber zone
      const u = t / 0.4;
      const r = Math.round(200 + (251 - 200) * u);
      const g = Math.round(180 + (191 - 180) * u);
      const b = Math.round(60  + (36  - 60)  * u);
      return `rgb(${r},${g},${b})`;
    } else {
      // red zone
      const u = (t - 0.4) / 0.6;
      const r = Math.round(251 + (248 - 251) * u);
      const g = Math.round(191 + (113 - 191) * u);
      const b = Math.round(36  + (113 - 36)  * u);
      return `rgb(${r},${g},${b})`;
    }
  }
}

function buildPxChg(s) {
  if (s.livePxChange == null) return '<span class="px-chg-nil">—</span>';
  const v = s.livePxChange;
  const col = gradientPctColor(v, 5);
  return '<span style="color:' + col + ';font-family:\'DM Mono\',monospace;font-size:12px;font-weight:600">' + (v > 0 ? '+' : '') + v.toFixed(1) + '%</span>';
}

function buildDeltaPct(v, maxMag) {
  if (v === null || v === undefined || isNaN(v)) return '<span style="color:var(--text3);font-family:\'DM Mono\',monospace;font-size:12px">—</span>';
  const col = gradientPctColor(v, maxMag || 20);
  return '<span style="color:' + col + ';font-family:\'DM Mono\',monospace;font-size:12px;font-weight:600">' + (v > 0 ? '+' : '') + v.toFixed(1) + '%</span>';
}


/* ═══════════════════════════════════════════════════
   COUNTRY TABS
═══════════════════════════════════════════════════ */
var _activeCountryTab = 'All';

function buildCountryTabs() {
  const bar = document.getElementById('countryTabBar');
  if (!bar) return;

  // Count stocks per country
  const counts = {};
  let total = 0;
  Object.values(STOCKS).forEach(s => {
    const c = _country(s);
    counts[c] = (counts[c] || 0) + 1;
    total++;
  });

  const countryOrder = ['United States','Hong Kong / China','United Kingdom','Europe','Singapore','Japan','Korea','Australia','Other'];
  const countries = countryOrder.filter(c => counts[c]);

  bar.innerHTML = '';

  // "All" tab
  const allTab = document.createElement('button');
  allTab.className = 'country-tab' + (_activeCountryTab === 'All' ? ' active' : '');
  allTab.innerHTML = 'All <span class="tab-count">' + total + '</span>';
  allTab.onclick = () => setCountryTab('All');
  bar.appendChild(allTab);

  countries.forEach(c => {
    const tab = document.createElement('button');
    tab.className = 'country-tab' + (_activeCountryTab === c ? ' active' : '');
    const label = c.replace(' / China','').replace('United ','');
    tab.innerHTML = label + ' <span class="tab-count">' + counts[c] + '</span>';
    tab.onclick = () => setCountryTab(c);
    bar.appendChild(tab);
  });
}

function setCountryTab(country) {
  _activeCountryTab = country;
  // Update tab active states
  document.querySelectorAll('.country-tab').forEach(tab => {
    const label = tab.textContent.replace(/\d+/g,'').trim();
    const isAll = country === 'All' && (label === 'All' || label.trim() === 'All');
    const matches = country !== 'All' && (
      country.includes(label) || label.includes(label.split(' ')[0])
    );
    tab.classList.toggle('active', tab.onclick.toString().includes("'" + country + "'") || tab.onclick.toString().includes('"' + country + '"'));
  });
  // Rebuild properly
  buildCountryTabs();
  applyAllFilters();
}


function setPriorityFilter(val) {
  document.querySelectorAll('.pf-chip').forEach(b => b.classList.remove('pf-active'));
  const btn = document.getElementById('pf-' + val);
  if (btn) btn.classList.add('pf-active');
  const hidden = document.getElementById('priorityFilter');
  if (hidden) hidden.value = val;

  // Update count badge
  const counts = { all:0, bought:0, watchlist:0, backburner:0 };
  Object.values(STOCKS).forEach(s => {
    counts.all++;
    const p = (s.priority || '').toLowerCase();
    if (p === 'bought') counts.bought++;
    else if (p === 'watchlist') counts.watchlist++;
    else if (p === 'backburner') counts.backburner++;
  });
  const countEl = document.getElementById('priorityCount');
  if (countEl) {
    const n = counts[val] !== undefined ? counts[val] : counts.all;
    countEl.textContent = n + ' stocks';
  }
  applyAllFilters();
}

function applyAllFilters() {
  const tbody = document.getElementById('watchlistBody');
  if (!tbody) return;
  const searchVal = (document.getElementById('searchInput')?.value || '').toLowerCase();
  const ratingVal = document.querySelector('.rating-chip.active')?.getAttribute('data-rating') || 'all';
  const priorityVal = (document.getElementById('priorityFilter')?.value || 'all').toLowerCase();

  let visible = 0;
  Array.from(tbody.querySelectorAll('tr[data-ticker]')).forEach(tr => {
    const ticker = tr.getAttribute('data-ticker');
    const s = STOCKS[ticker];
    if (!s) { tr.style.display = 'none'; return; }

    // Country filter
    if (_activeCountryTab !== 'All' && _country(s) !== _activeCountryTab) {
      tr.style.display = 'none'; return;
    }
    // Rating filter
    if (ratingVal !== 'all' && s.rating !== ratingVal) {
      tr.style.display = 'none'; return;
    }
    // Priority filter
    if (priorityVal !== 'all') {
      const p = (s.priority || '').toLowerCase();
      if (priorityVal === 'bought' && p !== 'bought') { tr.style.display = 'none'; return; }
      if (priorityVal === 'watchlist' && p !== 'watchlist') { tr.style.display = 'none'; return; }
      if (priorityVal === 'backburner' && p !== 'backburner') { tr.style.display = 'none'; return; }
    }
    // Search filter
    if (searchVal) {
      const hay = (s.ticker + ' ' + s.name + ' ' + s.sector).toLowerCase();
      if (!hay.includes(searchVal)) { tr.style.display = 'none'; return; }
    }

    tr.style.display = '';
    visible++;
  });

  const countEl = document.getElementById('filterCount');
  if (countEl) countEl.textContent = visible + ' stocks';

  // Hide/show sector header rows based on visible siblings
  Array.from(tbody.querySelectorAll('tr.sector-header, tr.country-header, tr.subsector-header')).forEach(hr => {
    let next = hr.nextElementSibling;
    let hasVisible = false;
    while (next && !next.classList.contains('country-header') && !next.classList.contains('sector-header')) {
      if (next.style.display !== 'none' && next.hasAttribute('data-ticker')) hasVisible = true;
      next = next.nextElementSibling;
    }
    hr.style.display = hasVisible ? '' : 'none';
  });
}


function buildW52Bar(s) {
  if (!s.week52High || !s.week52Low || s.week52High <= s.week52Low) return '<span class="px-chg-nil">—</span>';
  const pct = Math.max(0, Math.min(100, (s.livePrice - s.week52Low) / (s.week52High - s.week52Low) * 100));
  // Green near 0% (near 52w low), red near 100% (near 52w high)
  const r = Math.round(pct * 2.55);
  const g = Math.round((100 - pct) * 2.0);
  const dotColor = 'rgb(' + r + ',' + g + ',60)';
  return '<div class="w52-bar-wrap">' +
    '<div class="w52-track"><div class="w52-slider-dot" style="left:' + pct.toFixed(1) + '%;background:' + dotColor + '"></div></div>' +
    '<span class="w52-pct" style="left:' + pct.toFixed(1) + '%">' + pct.toFixed(0) + '%</span>' +
    '</div>';
}

function buildEntryFlag(entryDiff) {
  if (entryDiff <= 0) {
    return '<span class="entry-flag at-entry" title="AT or BELOW entry target">' + entryDiff.toFixed(1) + '% \u2713</span>';
  } else if (entryDiff <= 5) {
    return '<span class="entry-flag near-entry" title="Within 5% of entry target">+' + entryDiff.toFixed(1) + '% \u25b2</span>';
  } else {
    return '<span class="entry-flag above-entry">+' + entryDiff.toFixed(1) + '%</span>';
  }
}

function updateTableRow(s) {
  const upside     = ((s.targetPrice - s.livePrice) / s.livePrice * 100);
  const reportDiff = ((s.livePrice - s.reportPrice) / s.reportPrice * 100);
  const entryDiff  = ((s.livePrice - s.entryPrice)  / s.entryPrice  * 100);

  const tr = document.querySelector('#watchlistBody tr[data-ticker="' + s.ticker + '"]');
  const liveEl   = document.getElementById('tbl-live-'      + s.ticker);
  const pxchgEl  = document.getElementById('tbl-pxchg-'     + s.ticker);
  const w52El    = document.getElementById('tbl-w52-'        + s.ticker);
  const rdiffEl  = document.getElementById('tbl-rdiff-'     + s.ticker);
  const upsideEl = document.getElementById('tbl-upside-'    + s.ticker);
  const flagEl   = document.getElementById('tbl-entryflag-' + s.ticker);

  if (liveEl)   liveEl.innerHTML  = '<span class="price-mono">$' + fmtPrice(s.livePrice) + '</span>';
  if (pxchgEl)  pxchgEl.innerHTML = buildPxChg(s);
  if (w52El)    w52El.innerHTML   = buildW52Bar(s);
  if (rdiffEl)  rdiffEl.innerHTML = buildDeltaPct(reportDiff, 25);
  if (upsideEl) upsideEl.innerHTML= buildDeltaPct(upside, 50);
  if (flagEl)   flagEl.innerHTML  = buildEntryFlag(entryDiff);

  // Update SQ/Dis pill
  if (tr) {
    var sqPill = tr.querySelector('.sq-pill');
    if (sqPill) sqPill.innerHTML = '<span class="sq-dot" style="background:' + sqColor(s.sqScore) + '"></span>' + s.sqScore + '/' + (s.dislocationScore || s.dislocationAtReport);
  }

  // Update rating badge if cached action badge exists (from live refresh)
  if (tr && s._cachedActionBadge) {
    var ratingTd = tr.querySelector('.rating-badge');
    if (ratingTd) {
      var newRating = s._cachedActionBadge.text.replace(/[↑↓] /g, '').trim();
      var ratingClass = newRating === 'BUY' ? 'BUY' : newRating === 'HOLD' ? 'HOLD' : newRating === 'WAIT' ? 'WAIT' : newRating === 'SELL' ? 'SELL' : s.rating;
      ratingTd.className = 'rating-badge ' + ratingClass;
      ratingTd.textContent = newRating;
      // Update row left border
      tr.className = ratingClass;
    }
  }

  // Update header stats
  var stocks = Object.values(STOCKS);
  var buys = stocks.filter(function(st) {
    if (st._cachedActionBadge) {
      var r = st._cachedActionBadge.text.replace(/[↑↓] /g, '').trim();
      return r === 'BUY';
    }
    return st.rating === 'BUY';
  }).length;
  var avgUp = stocks.reduce(function(a, st) { return a + ((st.targetPrice - st.livePrice) / st.livePrice * 100); }, 0) / stocks.length;
  document.getElementById('statBuys').textContent = buys;
  document.getElementById('statAvgUpside').textContent = avgUp.toFixed(1) + '%';
}


function sqColor(score) {
  if (score >= 8) return 'var(--green)';
  if (score >= 6) return 'var(--amber)';
  return 'var(--red)';
}

function memoAge(dateStr) {
  const d = new Date(dateStr);
  const today = new Date();
  today.setHours(0,0,0,0);
  d.setHours(0,0,0,0);
  return Math.floor((today - d) / 86400000);
}

/* ═══════════════════════════════════════════════════
   OPEN CARD MODAL
═══════════════════════════════════════════════════ */
function renderScoreExplain(containerId, items, score, scoreElId) {
  var el = document.getElementById(containerId);
  var scoreEl = document.getElementById(scoreElId);
  if (!items || !items.length) { el.innerHTML = '<div style="font-size:10px;color:var(--text3)">See report for details</div>'; scoreEl.textContent = score + '/10'; scoreEl.style.color = sqColor(score); return; }
  scoreEl.textContent = score + '/10';
  scoreEl.style.color = sqColor(score);
  el.innerHTML = items.map(function(it) {
    var dotCls = it.sentiment === 'positive' ? 'green' : it.sentiment === 'negative' ? 'red' : 'amber';
    return '<div class="score-explain-item ' + it.sentiment + '"><div class="score-explain-factor"><span class="se-dot ' + dotCls + '"></span>' + it.factor + '</div><div class="score-explain-detail">' + it.detail + '</div></div>';
  }).join('');
}

function openCard(ticker) {
  const s = STOCKS[ticker];
  currentStock = s;

  // card border class
  const shell = document.getElementById('cardShell');
  shell.className = 'card-shell ' + s.rating;

  // action header
  document.getElementById('cardActionBadge').textContent = s.rating;
  document.getElementById('cardActionBadge').className = 'action-badge ' + s.rating;
  document.getElementById('cardInstruction').textContent = s._cachedInstruction || s.instruction;
  document.getElementById('cardTrigger').textContent = s._cachedTrigger || s.trigger;

  // stale badge
  const days = memoAge(s.reportDate);
  const staleBadge = document.getElementById('cardStaleBadge');
  if (days === 0)       { staleBadge.textContent = 'Today'; staleBadge.className = 'stale-badge fresh'; }
  else if (days <= 30)  { staleBadge.textContent = days + 'd old'; staleBadge.className = 'stale-badge recent'; }
  else if (days <= 90)  { staleBadge.textContent = '⚠ ' + days + 'd old'; staleBadge.className = 'stale-badge old'; }
  else                  { staleBadge.textContent = '⚠ STALE ' + days + 'd'; staleBadge.className = 'stale-badge stale'; }

  // scores — use live dislocation if available, else fall back to data value
  document.getElementById('cardSQ').textContent = s.sqScore;
  document.getElementById('cardSQ').style.color = sqColor(s.sqScore);
  const dispDislo = s.dislocationScore || s.dislocationAtReport;
  document.getElementById('cardDislocation').innerHTML = dispDislo + ' <span style="font-size:11px;color:var(--text3)">(' + s.dislocationAtReport + ')</span>';
  document.getElementById('cardDislocation').style.color = sqColor(dispDislo);

  // restore cached refresh state if available, otherwise reset
  if (s._cachedThesisBanner) {
    document.getElementById('thesisBanner').className = s._cachedThesisBanner.cls;
    document.getElementById('thesisBanner').textContent = s._cachedThesisBanner.text;
  } else {
    document.getElementById('thesisBanner').className = 'thesis-banner';
    document.getElementById('thesisBanner').textContent = '';
  }
  if (s._cachedActionBadge) {
    const badge = document.getElementById('cardActionBadge');
    badge.textContent = s._cachedActionBadge.text;
    badge.className   = s._cachedActionBadge.cls;
  }
  if (s._cachedAdviceHTML) {
    document.getElementById('updatedAdvice').innerHTML = s._cachedAdviceHTML;
    document.getElementById('assessmentTime').textContent = s._cachedAssessmentTime || '';
    document.getElementById('lastRefreshed').textContent = s._cachedLastRefreshed || '';
  } else {
    document.getElementById('lastRefreshed').textContent = 'Never refreshed';
    document.getElementById('updatedAdvice').innerHTML = '<span style="color:var(--text3);font-size:11px;">Press <strong style="color:var(--blue)">Live Refresh</strong> to pull latest AI assessment.</span>';
    document.getElementById('assessmentTime').textContent = 'Not refreshed';
  }

  // zone 1 left
  document.getElementById('z1Ticker').textContent = s.ticker;
  document.getElementById('z1Name').textContent = s.name;
  document.getElementById('z1Meta').innerHTML = [s.exchange, s.currency, s.sector, 'Report: ' + s.reportDate]
    .map(m => `<span class="meta-chip">${m}</span>`).join('');

  // ── COMPANY INTRO ──
  var introWrapper = document.getElementById('z1CompanyIntro');
  var introText = document.getElementById('z1CompanyIntroText');
  if (introWrapper && introText) {
    if (s.companyIntro) {
      introText.textContent = s.companyIntro;
      introWrapper.style.display = 'block';
    } else {
      introWrapper.style.display = 'none';
    }
  }

  // ── INDUSTRY ANALYSIS ──
  var indEl1 = document.getElementById('z1IndustryStats');
  var indEl2 = document.getElementById('z1IndustryPeers');
  var indEl3 = document.getElementById('z1IndustryDrivers');
  if (s.industryData) {
    indEl1.innerHTML = s.industryData.stats.map(function(st) {
      return '<div class="industry-stat"><div class="industry-stat-label">' + st.label + '</div><div class="industry-stat-value">' + st.value + '</div><div class="industry-stat-sub">' + st.sub + '</div></div>';
    }).join('');
    if (s.industryData.peers && s.industryData.peers.length) {
      indEl2.innerHTML = '<table class="industry-peers-table"><thead><tr><th>Ticker</th><th>Fwd P/E</th><th>Rev Gr.</th><th>SQ</th><th>Dis.</th><th>Moat</th></tr></thead><tbody>' +
        s.industryData.peers.map(function(p) {
          var estSQ = p.sq || '—';
          var estDis = p.dis || '—';
          var sqC = typeof p.sq === 'number' ? 'color:' + sqColor(p.sq) : '';
          var disC = typeof p.dis === 'number' ? 'color:' + sqColor(p.dis) : '';
          var revGr = p.revGrowth || p.roic || '—';
          return '<tr><td>' + p.name + '</td><td>' + p.pe + '</td><td>' + revGr + '</td><td style="' + sqC + '">' + estSQ + '</td><td style="' + disC + '">' + estDis + '</td><td style="color:var(--text2);font-family:DM Sans,sans-serif">' + (p.moatDetail || p.moat) + '</td></tr>';
        }).join('') +
        '</tbody></table>';
    } else { indEl2.innerHTML = ''; }
    indEl3.innerHTML = s.industryData.drivers.map(function(d) {
      return '<div class="industry-driver ' + d.type + '">' + d.text + '</div>';
    }).join('');
  } else {
    indEl1.innerHTML = '';
    indEl2.innerHTML = '';
    indEl3.innerHTML = '';
  }

  const bullets = document.getElementById('z1Bullets');
  // Split bullets into thesis bullets and risk/signal bullets
  const filteredBullets = s.thesisBullets.filter(b => {
    const stripped = b.replace(/<[^>]+>/g, '').toLowerCase();
    return !stripped.startsWith('key risk:') && !stripped.startsWith('signal:') && !stripped.startsWith('re-rating trigger:');
  });
  const riskBullets = s.thesisBullets.filter(b => {
    const stripped = b.replace(/<[^>]+>/g, '').toLowerCase();
    return stripped.startsWith('key risk:') || stripped.startsWith('signal:') || stripped.startsWith('re-rating trigger:');
  });
  bullets.innerHTML = filteredBullets.map(b => `<li>${b}</li>`).join('');

  // Render risks / signals below thesis bullets
  var risksEl = document.getElementById('z1RisksBullets');
  if (risksEl) {
    if (riskBullets.length > 0) {
      risksEl.innerHTML =
        '<div style="margin-top:8px;padding:8px 11px;background:rgba(248,113,113,.05);border:1px solid rgba(248,113,113,.18);border-radius:5px;border-left:3px solid var(--red)">' +
        '<div style="font-size:8px;font-weight:700;letter-spacing:.1em;color:var(--red);text-transform:uppercase;margin-bottom:5px">⚠ Key Risks &amp; Signals to Watch</div>' +
        '<ul class="bullet-list" style="margin-bottom:0">' +
        riskBullets.map(b => `<li style="font-size:11px">${b}</li>`).join('') +
        '</ul></div>';
    } else {
      risksEl.innerHTML = '';
    }
  }

  // ── MOAT WITH STRENGTH BADGES ──
  const moat = document.getElementById('z1Moat');
  moat.innerHTML = s.moatItems.map(m => {
    var str = m.strength || 'moderate';
    return `<div class="moat-item">
      <div class="moat-item-label"><span>${m.label}</span><span class="moat-strength ${str}">${str}</span></div>
      <div class="moat-item-value">${m.text}</div>
      <div class="moat-bar-outer_"><div class="moat-bar-fill_ ${str}"></div></div>
    </div>`;
  }).join('');

  // ── SCORE EXPLANATIONS ──
  renderScoreExplain('z1SQExplain', s.sqExplain, s.sqScore, 'z1SQScoreInline');
  renderScoreExplain('z1DisExplain', s.dislocationExplain, s.dislocationAtReport, 'z1DisScoreInline');

  // zone 1 right — prices (s.livePrice already updated if previously refreshed)
  const livePx = s.livePrice;
  const prefix = s.currency === 'USD' ? '$' : s.currency + ' ';
  document.getElementById('z1LivePrice').textContent = prefix + fmtPrice(livePx);
  const chg = ((livePx - s.reportPrice) / s.reportPrice * 100);
  document.getElementById('z1PriceChg').textContent = (chg >= 0 ? '+' : '') + chg.toFixed(1) + '% vs report';
  document.getElementById('z1PriceChg').style.color = chg >= 0 ? 'var(--green)' : 'var(--red)';
  document.getElementById('z1ReportPrice').textContent = prefix + fmtPrice(s.reportPrice);
  document.getElementById('z1ReportDate').textContent = 'Memo: ' + s.reportDate;
  document.getElementById('z1PWTarget').textContent = prefix + fmtPrice(s.targetPrice);
  const pwUp = ((s.targetPrice - livePx) / livePx * 100);
  document.getElementById('z1PWUpside').textContent = (pwUp >= 0 ? '+' : '') + pwUp.toFixed(1) + '%';
  document.getElementById('z1PWUpside').style.color = pwUp >= 0 ? 'var(--green)' : 'var(--red)';
  document.getElementById('z1Entry').textContent = prefix + fmtPrice(s.entryPrice);
  const entryPct = ((s.entryPrice - livePx) / livePx * 100);
  document.getElementById('z1EntryPct').textContent = (entryPct >= 0 ? '+' : '') + entryPct.toFixed(1) + '% from live';
  // Show entry note if available
  var entryNoteEl = document.getElementById('z1EntryNote');
  if (entryNoteEl) entryNoteEl.textContent = s.entryNote || '';
  var entryTriggerEl = document.getElementById('z1EntryTrigger');
  if (entryTriggerEl) entryTriggerEl.textContent = s.entryTrigger ? '⚡ ' + s.entryTrigger : '';

  // ── EARNINGS & RETURNS PROFILE ──
  // Format live market cap from sheet input
  var fmtMktCap = function(v) {
    if (!v || v <= 0) return '—';
    if (v >= 1e12) return '$' + (v / 1e12).toFixed(2).replace(/\.?0+$/, '') + 'T';
    if (v >= 1e9)  return '$' + (v / 1e9).toFixed(1)  + 'B';
    if (v >= 1e6)  return '$' + (v / 1e6).toFixed(1)  + 'M';
    // Value likely already parsed from "61.9B" string → raw = 61.9 → treat as billions
    if (v >= 1000) return '$' + (v / 1000).toFixed(2).replace(/\.?0+$/, '') + 'T';
    return '$' + v.toFixed(1) + 'B';
  };
  var liveMktCapVal = s.liveMarketCap || null;
  var mktCapBox = '<div class="fin-hl-item"><div class="fin-hl-label">Market Cap</div>' +
    '<div class="fin-hl-value">' + fmtMktCap(liveMktCapVal) + '</div>' +
    '<div class="fin-hl-sub">Live (from sheet)</div></div>';

  // Headline stat boxes (always shown — use headlineStats if present, else derive from financials)
  // First box is always live Market Cap; remaining 3 come from headlineStats/financials
  // PEG box — always the 2nd slot; calculated from reportPE / implied EPS growth or explicit field
  var pegValue = '—';
  var pegSub   = 'N/A';
  // Live P/E for PEG = live price ÷ fwdEPS (consistent with refreshMultiples)
  var livePEforPEG = (s.fwdEPS && s.fwdEPS > 0) ? (livePx / s.fwdEPS) : null;
  if (s.peg != null) {
    // Explicit PEG override on stock object
    pegValue = s.peg.toFixed(2) + 'x';
    pegSub   = 'Live P/E ÷ fwd EPS growth';
  } else if (livePEforPEG) {
    // Derive EPS growth: prefer explicit epsGrowth field, then historicalTable fcagr, then fwdEPSGrowth
    var impliedGrowth = null;
    if (s.epsGrowth && s.epsGrowth > 0) {
      impliedGrowth = s.epsGrowth;
    } else if (s.fwdEPSGrowth && s.fwdEPSGrowth > 0) {
      impliedGrowth = s.fwdEPSGrowth;
    } else if (s.historicalTable && s.historicalTable.rows) {
      var epsRow = s.historicalTable.rows.find(function(r) { return r.label && r.label.toLowerCase().includes('eps'); });
      if (epsRow && epsRow.fcagr && epsRow.fcagr !== '—') {
        var gc = parseFloat(epsRow.fcagr);
        if (!isNaN(gc) && gc > 0) impliedGrowth = gc;
      }
    }
    if (impliedGrowth && impliedGrowth > 0) {
      var pegCalc = (livePEforPEG / impliedGrowth).toFixed(2);
      pegValue = pegCalc + 'x';
      pegSub   = livePEforPEG.toFixed(1) + 'x live P/E ÷ ' + impliedGrowth.toFixed(1) + '% gr';
    }
  }
  var pegBox = '<div class="fin-hl-item"><div class="fin-hl-label">PEG Ratio</div>' +
    '<div class="fin-hl-value" style="color:' + (pegValue !== '—' ? (parseFloat(pegValue) < 1 ? 'var(--green)' : parseFloat(pegValue) < 2 ? 'var(--amber)' : 'var(--text)') : 'var(--text3)') + '">' + pegValue + '</div>' +
    '<div class="fin-hl-sub">' + pegSub + '</div></div>';

  var hlItems;
  if (s.headlineStats) {
    // skip any headlineStats slot that's already "PEG" to avoid duplication
    var filteredStats = s.headlineStats.filter(function(h) { return !h.label.toLowerCase().includes('peg'); });
    hlItems = filteredStats.slice(0, 2).map(function(h) {
      return '<div class="fin-hl-item"><div class="fin-hl-label">' + h.label + '</div>' +
             '<div class="fin-hl-value">' + h.value + '</div>' +
             '<div class="fin-hl-sub">' + (h.sub || '') + '</div></div>';
    });
  } else {
    // Fallback: derive 2 highlight boxes from existing financials array
    var hlSrc = (s.financials || []).slice(0, 2);
    hlItems = hlSrc.map(function(f) {
      var col = f.color || '';
      return '<div class="fin-hl-item"><div class="fin-hl-label">' + f.label + '</div>' +
             '<div class="fin-hl-value" style="' + (col ? 'color:' + col : '') + '">' + f.value + '</div>' +
             '<div class="fin-hl-sub">' + (f.trend || '') + '</div></div>';
    });
  }
  document.getElementById('z1FinHeadline').innerHTML = mktCapBox + pegBox + hlItems.join('');

  // Historical + forecast table (only if historicalTable data present)
  var tableWrap = document.getElementById('z1FinTableWrap');
  var tableEl   = document.getElementById('z1FinTable');
  var stripEl   = document.getElementById('z1FinStrip');
  if (s.historicalTable) {
    tableWrap.style.display = '';
    stripEl.style.display   = 'none';
    var ht = s.historicalTable;
    // Build header
    var hdrCells = '<th>' + (ht.metricLabel || 'Metric') + '</th>';
    ht.years.forEach(function(y, i) {
      var cls = y === 'CAGR' ? 'cagr' : y === 'Fwd' ? 'fwd-cagr' : (i <= 3 ? (i % 2 === 0 ? 'hist-a' : 'hist-b') : 'fwd');
      hdrCells += '<th class="' + cls + '">' + y + '</th>';
    });
    var html = '<thead><tr>' + hdrCells + '</tr></thead><tbody>';
    ht.rows.forEach(function(row) {
      var trClass = row.highlight ? ' class="fin-row-highlight"' : '';
      html += '<tr' + trClass + '><td>' + row.label + '</td>';
      row.hist.forEach(function(v, i) {
        html += '<td class="' + (i % 2 === 0 ? 'hist-a' : 'hist-b') + '">' + v + '</td>';
      });
      html += '<td class="cagr">' + (row.hcagr || '—') + '</td>';
      row.fwd.forEach(function(v) {
        html += '<td class="fwd">' + v + '</td>';
      });
      html += '<td class="fwd-cagr">' + (row.fcagr || '—') + '</td>';
      html += '</tr>';
    });
    html += '</tbody>';
    tableEl.innerHTML = html;
  } else {
    // Fallback: use the old fin-strip cards
    tableWrap.style.display = 'none';
    stripEl.style.display   = '';
    var finItems = (s.financials || []).map(function(f) {
      if (f.label === 'ROIC' && s.roic && s.wacc) {
        var spread = s.roic - s.wacc;
        var spreadColor = spread > 5 ? 'var(--green)' : spread > 0 ? 'var(--amber)' : 'var(--red)';
        var spreadVerdict = spread > 10 ? 'Exceptional creator' : spread > 5 ? 'Strong creator' : spread > 0 ? 'Marginal — monitor' : 'Below cost of capital';
        return '<div class="fin-item"><div class="fin-label">' + f.label + '</div>' +
               '<div class="fin-value" style="color:' + spreadColor + '">' + f.value + '</div>' +
               '<div class="fin-trend up" style="color:' + spreadColor + '">' + (spread > 0 ? '+' : '') + spread + 'pp · ' + spreadVerdict + '</div></div>';
      }
      return '<div class="fin-item"><div class="fin-label">' + f.label + '</div>' +
             '<div class="fin-value" style="' + (f.color ? 'color:' + f.color : '') + '">' + f.value + '</div>' +
             '<div class="fin-trend ' + (f.dir || '') + '">' + f.trend + '</div></div>';
    });
    stripEl.innerHTML = finItems.join('');
  }

  // Contextual fin note
  var finNoteEl = document.getElementById('z1FinNote');
  if (finNoteEl) finNoteEl.textContent = s.finNote;

  // range bar
  renderRangeBar(s);

  // multiples — initial render using report price; refreshMultiples() called after live refresh
  refreshMultiples(s);

  // scatter — render watchlist comparison chart
  setTimeout(function() { renderScatter(s); }, 50);

  // PWT row
  document.getElementById('z1PWTRow').innerHTML = `
    <div class="pwt-scenario">
      <div class="pwt-label_" style="color:var(--green)">Bull ${s.bullProb}%</div>
      <div class="pwt-price_" style="color:var(--green)">$${s.bullCase}</div>
      <div class="pwt-prob_">${s.bullMultiple}</div>
    </div>
    <div class="pwt-scenario">
      <div class="pwt-label_" style="color:var(--blue)">Base ${s.baseProb}%</div>
      <div class="pwt-price_" style="color:var(--blue)">$${s.baseCase}</div>
      <div class="pwt-prob_">${s.baseMultiple}</div>
    </div>
    <div class="pwt-scenario">
      <div class="pwt-label_" style="color:var(--red)">Bear ${s.bearProb}%</div>
      <div class="pwt-price_" style="color:var(--red)">$${s.bearCase}</div>
      <div class="pwt-prob_">${s.bearMultiple}</div>
    </div>
    <div class="pwt-final">
      <div class="pwt-final-label">PW Target</div>
      <div class="pwt-final-value">$${fmtPrice(s.targetPrice)}</div>
      <div class="pwt-final-sub" style="color:var(--green)">${pwUp >= 0 ? '+' : ''}${pwUp.toFixed(1)}% upside</div>
      <div class="pwt-final-sub" style="color:var(--red)">Bear: ${(((s.bearCase - livePx)/livePx)*100).toFixed(1)}%</div>
    </div>`;

  const udRatio = pwUp / Math.abs(((s.bearCase - livePx)/livePx*100));
  document.getElementById('z1PWTRatio').innerHTML = `Upside/Downside Ratio: <strong style="color:var(--blue)">${udRatio.toFixed(1)}x</strong> — ${udRatio >= 2.5 ? 'High conviction' : udRatio >= 1.5 ? 'Moderate conviction' : 'Low conviction'} (threshold: >2.5x)`;

  // zone 2 debates
  renderDebates(s);
  document.getElementById('netSentimentBadge').textContent = s.netSentiment.replace('_', ' ');
  document.getElementById('netSentimentBadge').className = 'net-sentiment-badge ' + s.netSentiment;
  document.getElementById('netSentimentText').textContent = s.netSentimentText;
  document.getElementById('thesisHinge').textContent = s.thesisHinge;

  // zone 3 financials
  document.getElementById('finNote').textContent = s.finNote;

  // catalyst timeline removed

  // zone 4 capital advice
  var capRec = document.getElementById('capOrigRec');
  var capRating = s._cachedCapRating || s.rating;
  capRec.className = 'cap-final-rec ' + capRating;
  var advBox = document.getElementById('adviceBox');
  advBox.innerHTML = s.capitalAdvice;
  // Conviction trigger
  var ctBox = document.getElementById('convictionTriggerBox');
  var ctText = document.getElementById('convictionTriggerText');
  if (s.convictionText && ctBox && ctText) {
    ctText.innerHTML = s.convictionText;
    ctBox.style.display = 'block';
  } else if (ctBox) {
    ctBox.style.display = 'none';
  }
  // Better alt rendered in zone1 only
  document.getElementById('z1BetterAlt').innerHTML = s.betterAlt;

  // open modal
  document.getElementById('modalOverlay').classList.add('open');
  document.body.style.overflow = 'hidden';
}

function closeCard() {
  document.getElementById('modalOverlay').classList.remove('open');
  document.body.style.overflow = '';
  currentStock = null;
}

function renderDebates(s) {
  document.getElementById('debatesGrid').innerHTML = s.debates.map(d => {
    // determine verdict from cached refresh if available
    const cached = s._cachedDebateUpdates && s._cachedDebateUpdates[d.id];
    const verdictClass = cached ? (['STRONGLY_BULLISH','BULL_LEANING','BULL_WINNING'].indexOf(cached.verdict) >= 0 ? 'bull' : ['STRONGLY_BEARISH','BEAR_LEANING','BEAR_WINNING'].indexOf(cached.verdict) >= 0 ? 'bear' : 'neutral') : 'neutral';
    const verdictLabel = cached ? (cached.verdict === 'STRONGLY_BULLISH' ? '▲▲ Strongly Bull' : cached.verdict === 'BULL_LEANING' ? '▲ Bull Leaning' : cached.verdict === 'STRONGLY_BEARISH' ? '▼▼ Strongly Bear' : cached.verdict === 'BEAR_LEANING' ? '▼ Bear Leaning' : cached.verdict === 'BULL_WINNING' ? '▲ Bull Winning' : cached.verdict === 'BEAR_WINNING' ? '▼ Bear Winning' : '◆ Neutral') : '—';
    const statusClass = cached ? cached.status : 'LIVE';
    const updateText = cached ? cached.update : 'Press Live Refresh to assess.';
    return `
    <div class="debate-card">
      <div class="debate-title">
        <span class="debate-num_">${d.id.replace('d','D')}</span>
        <span style="flex:1">${d.question}</span>
        <span class="debate-status ${statusClass}" id="${safeId(s.ticker)}-${d.id}-status">${statusClass}</span>
      </div>
      <div class="debate-resolution">${d.resolution || (d.bull + '<br><br><em style="color:var(--text3)">Bear case: ' + d.bear.substring(0,120) + '…</em>')}</div>
      <div class="debate-verdict-row">
        <span class="debate-verdict-label ${verdictClass}" id="${safeId(s.ticker)}-${d.id}-verdict">${verdictLabel}</span>
        <span class="debate-verdict-price" id="${safeId(s.ticker)}-${d.id}-prices">${d.bullNum} · ${d.bearNum}</span>
      </div>
      <div class="debate-update">
        <div class="debate-update-label">What's Changed Since Report</div>
        <div id="${safeId(s.ticker)}-${d.id}-loading" style="display:none" class="updating-inline"><div class="spin-dot"></div>Updating…</div>
        <div class="debate-update-content" id="${safeId(s.ticker)}-${d.id}-content">${updateText}</div>
      </div>
    </div>`;
  }).join('');
}

/* ═══════════════════════════════════════════════════
   REFRESH MULTIPLES (called on open + after live price)
═══════════════════════════════════════════════════ */
function refreshMultiples(s) {
  const px = s.livePrice;

  // Fwd P/E — always calculate from live price ÷ analyst fwdEPS (never use API-supplied P/E ratio,
  // which can be trailing, distorted, or mis-mapped from spreadsheet columns)
  let lpe = null, lpeStr = '—';
  if (s.fwdEPS && s.fwdEPS > 0) {
    lpe = parseFloat((px / s.fwdEPS).toFixed(1));
  }
  lpeStr = lpe ? lpe.toFixed(1) + 'x' : '—';
  const pePct = (lpe && s.histPELow && s.histPEHigh)
    ? Math.min(100, Math.max(0, (lpe - s.histPELow) / (s.histPEHigh - s.histPELow) * 100)) : 0;

  // EV/EBITDA
  let evEbitdaStr = s.reportEVEBITDA ? s.reportEVEBITDA + 'x' : '—';
  let evNote = 'At report date';
  if (s.liveEV && s.reportEBITDA) {
    const liveEvEbitda = (s.liveEV * 1000 / s.reportEBITDA).toFixed(1);
    evEbitdaStr = liveEvEbitda + 'x';
    evNote = 'Live EV / report EBITDA';
  } else if (s.liveEV && s.reportEVEBITDA && s.reportMarketCap) {
    const evRatio = s.liveEV / s.reportMarketCap;
    evEbitdaStr = (s.reportEVEBITDA * evRatio).toFixed(1) + 'x';
    evNote = 'Live-adjusted';
  }

  // Margin of Safety vs live price
  const liveMoS = s.targetPrice > 0 ? Math.round((s.targetPrice - px) / s.targetPrice * 100) : s.marginOfSafety;
  const mosPct = Math.min(100, Math.max(0, liveMoS / 50 * 100));
  const mosColor = liveMoS >= 30 ? 'var(--green)' : liveMoS >= 15 ? 'var(--amber)' : 'var(--red)';

  const peSubText = s.histPELow ? Math.round(pePct) + 'th pct (' + s.histPELow + 'x\u2013' + s.histPEHigh + 'x hist.)' : 'vs history N/A';
  const mosSubText = (liveMoS >= 30 ? 'Adequate' : liveMoS >= 15 ? 'Moderate' : 'Thin') + ' vs PW target (threshold: >30%)';
  const roicSpread = s.roic - s.wacc;
  const roicBarWidth = Math.min(100, s.roic / s.wacc * 100);

  document.getElementById('z1Multiples').innerHTML =
    '<div class="mult-item">' +
      '<div class="mult-label">Fwd P/E (Live)</div>' +
      '<div class="mult-value" id="livePEVal">' + lpeStr + '</div>' +
      '<div class="mult-bar-outer"><div class="mult-bar-fill" style="width:' + pePct + '%"></div></div>' +
      '<div class="mult-sub">' + peSubText + '</div>' +
    '</div>' +
    '<div class="mult-item">' +
      '<div class="mult-label">EV/EBITDA</div>' +
      '<div class="mult-value">' + evEbitdaStr + '</div>' +
      '<div class="mult-bar-outer"><div class="mult-bar-fill" style="width:25%"></div></div>' +
      '<div class="mult-sub">' + evNote + '</div>' +
    '</div>' +
    '';
}

/* ═══════════════════════════════════════════════════
   RANGE BAR
═══════════════════════════════════════════════════ */
function renderRangeBar(s) {
  // ── Bar 1: Live vs Scenarios (bear · base · PW target · bull)
  const min1 = s.bearCase;
  const max1 = s.bullCase;
  const pct1 = p => Math.max(0, Math.min(100, (p - min1) / (max1 - min1) * 100));
  const markers1 = [
    { label:'Live',      price:s.livePrice,  cls:'live',   color:'#22d3ee' },
    { label:'PW Target', price:s.targetPrice,cls:'target', color:'#f0c040' },
  ];
  const bar1 = document.getElementById('rangeBar1');
  bar1.querySelectorAll('.range-marker').forEach(m => m.remove());
  markers1.forEach(m => {
    const el = document.createElement('div');
    el.className = 'range-marker';
    el.style.left = pct1(m.price) + '%';
    el.title = m.label + ': $' + m.price;
    el.innerHTML = '<div class="range-marker-dot ' + m.cls + '"></div>';
    bar1.appendChild(el);
  });
  document.getElementById('rangeEnds1').innerHTML =
    '<span class="range-bar-end rbe-start">$' + s.bearCase + '<br><span class="rbe-label">(bear)</span></span>' +
    '<span class="range-bar-end rbe-mid" style="left:' + pct1(s.targetPrice) + '%">$' + s.targetPrice + '<br><span class="rbe-label">(pw target)</span></span>' +
    '<span class="range-bar-end rbe-end">$' + s.bullCase + '<br><span class="rbe-label">(bull)</span></span>';
  document.getElementById('rangeAbove1').innerHTML =
    '<div class="range-bar-above-label" style="left:' + pct1(s.livePrice) + '%">' +
      '$' + fmtPrice(s.livePrice || 0) + '<br><span class="rba-sub">(live)</span>' +
    '</div>';
  document.getElementById('rangeLegend1').innerHTML = '';

  // ── Bar 2: Live & Report vs 52W range
  const min2 = s.week52Low, max2 = s.week52High;
  const pct2 = p => Math.max(1, Math.min(99, (p - min2) / (max2 - min2) * 100));
  const markers2 = [
    { label:'Report',      price:s.reportPrice, cls:'report', color:'#c8d8f8' },
    { label:'Live',        price:s.livePrice,   cls:'live',   color:'#22d3ee' },
  ];
  const bar2 = document.getElementById('rangeBar2');
  bar2.querySelectorAll('.range-marker').forEach(m => m.remove());
  markers2.forEach(m => {
    const el = document.createElement('div');
    el.className = 'range-marker';
    el.style.left = pct2(m.price) + '%';
    el.title = m.label + ': $' + m.price;
    el.innerHTML = '<div class="range-marker-dot ' + m.cls + '"></div>';
    bar2.appendChild(el);
  });
  document.getElementById('rangeEnds2').innerHTML =
    '<span class="range-bar-end rbe-start">$' + s.week52Low + '<br><span class="rbe-label">(52w low)</span></span>' +
    '<span class="range-bar-end rbe-mid" style="left:' + pct2(s.reportPrice) + '%">$' + s.reportPrice + '<br><span class="rbe-label">(report)</span></span>' +
    '<span class="range-bar-end rbe-end">$' + s.week52High + '<br><span class="rbe-label">(52w high)</span></span>';
  document.getElementById('rangeAbove2').innerHTML =
    '<div class="range-bar-above-label" style="left:' + pct2(s.livePrice) + '%">' +
      '$' + fmtPrice(s.livePrice || 0) + '<br><span class="rba-sub">(live)</span>' +
    '</div>';
  document.getElementById('rangeLegend2').innerHTML = '';
}

/* ═══════════════════════════════════════════════════
   REFRESH ALL PRICES (bulk price update from main table)
═══════════════════════════════════════════════════ */
const SHEET_CSV_URL = 'https://docs.google.com/spreadsheets/d/e/2PACX-1vRowYEHwVGAzLs-fqF2obTNqnuGonIzhxk-aXIdyAEZTDFIcOVCmoT0DFbV87G3OiznoLrTswff3DT5/pub?output=csv';
// ── PASTE YOUR APPS SCRIPT WEB APP URL HERE after deploying (see instructions below) ──
const APPS_SCRIPT_URL = 'https://script.google.com/macros/s/AKfycbyVP_R5LQlIwnFk08gAya3ClBErxSuELZ3meQrCJkuvSTl-m-_bEy_gfVxktdHw3kX0/exec';

/* ═══════════════════════════════════════════════════
   APPLY PRICE STRING  (zero tokens, instant)
   Accepts formats:
     EXCHANGE:TICKER<price>  e.g.  NYSE:CCL23.92
     TICKER<price>           e.g.  CCL23.92
   Multiple pairs concatenated, whitespace optional.
═══════════════════════════════════════════════════ */
function applyPriceString() {
  const raw    = (document.getElementById('priceInput').value || '').trim();
  const status = document.getElementById('refreshAllStatus');
  if (!raw) { status.style.color = 'var(--amber)'; status.textContent = 'Nothing pasted yet'; return; }

  // Parse tab-separated rows: each line is TICKER  PRICE  [PXCHG%]  [MKTCAP]  [PE]
  // Ticker supports: letters, digits, dots, hyphens (e.g. 2018.HK, 000660.KS, BRK-B)
  const parseNum = v => { if (!v) return null; const n = parseFloat(String(v).replace(/[,$%\s]/g,'')); return isNaN(n) ? null : n; };
  let updated = 0, unknown = [];

  const lines = raw.split(/\r?\n/);
  for (const line of lines) {
    if (!line.trim()) continue;
    // Split on tabs; fall back to 2+ consecutive spaces if no tabs found
    let parts = line.trim().split(/\t/);
    if (parts.length < 2) parts = line.trim().split(/\s{2,}/);
    if (parts.length < 2) continue;
    let ticker = parts[0].toUpperCase().trim();
    if (!ticker) continue;
    const price = parseNum(parts[1]);
    if (!price || price <= 0) { unknown.push(ticker); continue; }
    // Normalize ticker: try direct, then variants for HK numeric codes
    if (!STOCKS[ticker]) {
      // Strip leading zeros: "00388" -> "388"
      const stripped = ticker.replace(/^0+/, '');
      // Try as HK ticker: "388" -> "388.HK", "0388.HK" -> "388.HK", "388:HK" -> "388.HK"
      const candidates = [
        ticker,
        stripped,
        ticker + '.HK',
        stripped + '.HK',
        ticker.replace(/[:\-]HK$/, '.HK'),
        stripped.replace(/[:\-]HK$/, '.HK'),
        ticker.replace(/\.HKG$/, '.HK'),
        ticker.replace(/^HK[:\-\.]/, '') + '.HK',
      ];
      let resolved = null;
      for (const c of candidates) { if (STOCKS[c]) { resolved = c; break; } }
      if (!resolved) { unknown.push(ticker); continue; }
      ticker = resolved;
    }

    const s = STOCKS[ticker];
    s.livePrice = price;

    // Optional columns: [2] px change %, [3] market cap, [4] fwd P/E (ignored — always calc from fwdEPS)
    if (parts[2] != null) { const v = parseNum(parts[2]); if (v != null) s.livePxChange = v; }
    if (parts[3] != null) { const v = parseNum(parts[3]); if (v && v > 0) s.liveMarketCap = v; }

    updateTableRow(s);
    // If this stock is currently open in the modal, refresh its live price display
    if (currentStock && currentStock.ticker === ticker) {
      document.getElementById('z1LivePrice').textContent = '$' + fmtPrice(price);
      const chg = ((price - currentStock.reportPrice) / currentStock.reportPrice * 100);
      document.getElementById('z1PriceChg').textContent = (chg >= 0 ? '+' : '') + chg.toFixed(1) + '% vs report';
      document.getElementById('z1PriceChg').style.color = chg >= 0 ? 'var(--green)' : 'var(--red)';
      refreshMultiples(currentStock);
      renderRangeBar(currentStock);
    }
    updated++;
  }

  // Re-render summary stats
  const stocks = Object.values(STOCKS);
  const buys = stocks.filter(s => s.rating === 'BUY').length;
  const avgUp = stocks.reduce((a,s) => a + ((s.targetPrice - s.livePrice)/s.livePrice*100), 0) / stocks.length;
  document.getElementById('statBuys').textContent = buys;
  document.getElementById('statAvgUpside').textContent = avgUp.toFixed(1) + '%';

  var _nd = new Date();
  var _months = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
  var nowLabel = _months[_nd.getMonth()] + ' ' + _nd.getDate() + ' ' + _nd.toLocaleTimeString('en-SG', { hour: '2-digit', minute: '2-digit' });
  if (updated === 0) {
    status.style.color = 'var(--red)';
    status.textContent = '✗ No tickers matched. Unknown: ' + unknown.slice(0,6).join(', ');
  } else {
    status.style.color = 'var(--green)';
    status.textContent = '✓ ' + updated + ' updated · ' + nowLabel + (unknown.length ? ' · ' + unknown.length + ' skipped' : '');
    document.getElementById('priceInput').value = '';
  }
}

// Robust CSV row parser — handles quoted fields containing commas
function parseCSVRow(line) {
  const result = [];
  let cur = '', inQ = false;
  for (let i = 0; i < line.length; i++) {
    const ch = line[i];
    if (ch === '"') {
      if (inQ && line[i+1] === '"') { cur += '"'; i++; }
      else inQ = !inQ;
    } else if (ch === ',' && !inQ) {
      result.push(cur.trim()); cur = '';
    } else {
      cur += ch;
    }
  }
  result.push(cur.trim());
  return result;
}

async function refreshAllPrices() {
  const btn    = document.getElementById('refreshAllBtn');
  const icon   = document.getElementById('refreshAllIcon');
  const status = document.getElementById('refreshAllStatus');

  btn.disabled = true;
  icon.classList.add('spin-anim');
  status.style.color = 'var(--text3)';
  status.textContent = 'Fetching…';

  try {
    // Fetch JSON from Google Apps Script web app (CORS-enabled, no API key needed)
    // Deploy your own: Extensions > Apps Script > paste APPS_SCRIPT_CODE > Deploy as Web App
    let csv = null;

    // Direct fetch from published CSV — works when sheet is published to web
    const directUrl = SHEET_CSV_URL + '&cachebust=' + Date.now();
    try {
      const r = await fetch(directUrl, { cache: 'no-store', mode: 'cors' });
      if (r.ok) {
        const t = await r.text();
        if (t && t.includes(',') && t.split('\n').length >= 2) csv = t;
      }
    } catch(e) {}

    // Fallback: Apps Script web app (user deploys once from their sheet)
    if (!csv && APPS_SCRIPT_URL) {
      try {
        // Apps Script returns CORS headers; follow redirects (GAS does a 302 first)
        const r = await fetch(APPS_SCRIPT_URL + '?cachebust=' + Date.now(), {
          cache: 'no-store',
          redirect: 'follow',
          mode: 'cors',
        });
        if (r.ok) {
          const json = await r.json();
          if (json && json.csv) csv = json.csv;
        }
      } catch(e) {
        // If CORS fails (e.g. file:// origin), try no-cors ping then re-fetch
        try {
          const r2 = await fetch(APPS_SCRIPT_URL + '?cachebust=' + Date.now(), {
            cache: 'no-store',
            redirect: 'follow',
          });
          if (r2.ok) {
            const json2 = await r2.json();
            if (json2 && json2.csv) csv = json2.csv;
          }
        } catch(e2) {}
      }
    }

    if (!csv || csv.split('\n').length < 2 || !csv.includes(',')) {
      throw new Error('Sheet fetch failed. See SETUP INSTRUCTIONS in the UPDATE button tooltip, or paste prices manually.');
    }

    // Parse CSV — handle quoted fields
    const allLines = csv.trim().split('\n');
    if (allLines.length < 2) throw new Error('Sheet has no data rows (only ' + allLines.length + ' line(s))');

    // ── Auto-detect header row ─────────────────────────────────────────
    // Sheet may have blank rows or title rows above the actual header.
    // Scan first 10 rows: pick the first row that either contains a known
    // header keyword OR whose cells match known tickers.
    const HEADER_KEYWORDS = ['ticker','symbol','price','last','change','market','52','name','company'];
    let headerRowIdx = 0;
    for (let li = 0; li < Math.min(10, allLines.length); li++) {
      const cells = parseCSVRow(allLines[li]).map(c => c.toLowerCase().replace(/[^a-z0-9]/g,' ').trim());
      // Check for header keywords
      if (cells.some(c => HEADER_KEYWORDS.some(k => c.includes(k)))) { headerRowIdx = li; break; }
      // Check if any cell matches a known ticker
      const upper = parseCSVRow(allLines[li]).map(c => c.toUpperCase().trim());
      if (upper.some(v => STOCKS[v])) { headerRowIdx = Math.max(0, li - 1); break; }
    }
    console.log('Auto-detected header row index:', headerRowIdx, '| content:', allLines[headerRowIdx]);

    const headers = parseCSVRow(allLines[headerRowIdx]).map(h => h.toLowerCase().replace(/[^a-z0-9]/g, ' ').trim());
    const rows    = allLines.slice(headerRowIdx + 1).map(l => parseCSVRow(l)).filter(r => r.some(c => c.trim()));

    // ── Flexible column detection ──────────────────────────────────────
    const findCol = (...keywords) => {
      for (let i = 0; i < headers.length; i++) {
        if (keywords.every(k => headers[i].includes(k))) return i;
      }
      return -1;
    };

    const col = {
      ticker  : findCol('ticker') !== -1 ? findCol('ticker') : findCol('symbol'),
      price   : findCol('price') !== -1  ? findCol('price')  : findCol('last'),
      mktcap  : findCol('market') !== -1 ? findCol('market') : findCol('cap'),
      pe      : findCol('p e') !== -1    ? findCol('p e')    : findCol('ratio'),
      high52  : (() => {
        for(let i=0;i<headers.length;i++) { if(headers[i].includes('52') && headers[i].includes('high') && !headers[i].includes('low')) return i; }
        for(let i=0;i<headers.length;i++) { if(headers[i].includes('high') && !headers[i].includes('low')) return i; }
        return -1;
      })(),
      low52   : (() => {
        for(let i=0;i<headers.length;i++) { if(headers[i].includes('52') && headers[i].includes('low') && !headers[i].includes('high')) return i; }
        for(let i=0;i<headers.length;i++) { if(headers[i].includes('low') && !headers[i].includes('high')) return i; }
        return -1;
      })(),
      // Combined "52W high-low" range column — value like "14.00 - 33.68"
      range52 : (() => {
        for(let i=0;i<headers.length;i++) {
          const h = headers[i];
          if(h.includes('52') && h.includes('high') && h.includes('low')) return i;
          if(h.includes('52') && h.includes('range')) return i;
          if(h.includes('range') && h.includes('high')) return i;
        }
        return -1;
      })(),
      pxchg   : (() => { for(let i=0;i<headers.length;i++) { const h=headers[i]; if((h.includes('change')||h.includes('chg'))&&!h.includes('52')) return i; } return -1; })(),
    };

    console.log('Sheet headers:', headers);
    console.log('Column map:', col);

    // If ticker still not found by header name, scan data rows for known tickers
    if (col.ticker < 0) {
      for (let c = 0; c < Math.min(5, (rows[0]||[]).length); c++) {
        const sampleVals = rows.slice(0,8).map(r => (r[c]||'').toUpperCase().trim());
        if (sampleVals.filter(v => STOCKS[v]).length >= 2) { col.ticker = c; break; }
      }
    }
    if (col.ticker < 0) throw new Error('Cannot find ticker column. Headers: [' + headers.join(' | ') + '] — ensure your sheet has a "Ticker Symbol" column header.');

    // If price not found by header, scan numeric columns
    if (col.price < 0) {
      for (let c = 0; c < (rows[0]||[]).length; c++) {
        if (c === col.ticker) continue;
        const vals = rows.slice(0,8).map(r => parseFloat(String(r[c]||'').replace(/[,$%]/g,'')));
        const valid = vals.filter(v => !isNaN(v) && v > 0.1 && v < 2000000);
        if (valid.length >= 3) { col.price = c; break; }
      }
    }
    if (col.price < 0) throw new Error('Cannot find price column. Headers: [' + headers.join(' | ') + ']');

    const parseNum = v => {
      if (v === undefined || v === null || v === '') return null;
      const n = parseFloat(String(v).replace(/[,$%\s]/g, ''));
      return isNaN(n) ? null : n;
    };

    // Build name->ticker lookup for HK fallback matching
    const nameToTicker = {};
    for (const [t, s] of Object.entries(STOCKS)) {
      if (s.name) nameToTicker[s.name.toLowerCase().trim()] = t;
    }

    // Detect name column for fallback
    const colName = (() => {
      for (let i = 0; i < headers.length; i++) {
        if (headers[i].includes('name') || headers[i].includes('company')) return i;
      }
      return -1;
    })();

    // Resolve raw ticker -> STOCKS key with exhaustive HK normalization + name fallback
    function resolveTicker(rawTicker, rawName) {
      let t = (rawTicker || '').toUpperCase().trim();
      if (!t) return null;
      if (STOCKS[t]) return t;

      // Strip exchange prefix (e.g. "NASDAQ:MSFT" -> "MSFT", "HKEX:388" -> "388")
      const noPrefix = t.replace(/^(NASDAQ|NYSE|AMEX|HKEX|HKG|HK|HSI|LON|TSX|ASX)[:\-\.\s]/, '');
      // Strip leading zeros
      const stripped = noPrefix.replace(/^0+/, '') || noPrefix;
      // Also strip .HK suffix to get bare number
      const bare = stripped.replace(/\.HK(G|EX)?$/, '').replace(/^0+/, '');

      const candidates = [
        noPrefix, stripped, bare,
        t + '.HK', noPrefix + '.HK', stripped + '.HK', bare + '.HK',
        t.replace(/[:\-]HK(G|EX)?$/, '.HK'),
        t.replace(/\.HKG$/, '.HK'),
        t.replace(/\.HKEX$/, '.HK'),
        // Zero-padded variants: "0388" -> "388.HK"
        bare.padStart(4,'0') + '.HK',
        bare.padStart(5,'0') + '.HK',
      ];
      for (const c of candidates) { if (c && STOCKS[c]) return c; }

      // Name fallback
      if (rawName) {
        const nl = rawName.toLowerCase().trim();
        if (nameToTicker[nl]) return nameToTicker[nl];
        for (const [sName, sTicker] of Object.entries(nameToTicker)) {
          if (nl.length > 4 && (sName.includes(nl) || nl.includes(sName))) return sTicker;
        }
      }
      return null;
    }

    let updated = 0;
    const skipped = [];
    for (const row of rows) {
      if (!row || row.length < 2) continue;
      const rawTicker = (row[col.ticker] || '').trim();
      if (!rawTicker) continue;
      const rawName = colName >= 0 ? (row[colName] || '') : '';
      const resolvedKey = resolveTicker(rawTicker, rawName);
      if (!resolvedKey) { skipped.push(rawTicker); continue; }

      const s = STOCKS[resolvedKey];
      const price = parseNum(row[col.price]);
      if (price && price > 0.01) { s.livePrice = price; }

      if (col.high52 >= 0) { const v = parseNum(row[col.high52]); if (v && v > 0) s.week52High = v; }
      if (col.low52  >= 0) { const v = parseNum(row[col.low52]);  if (v && v > 0) s.week52Low  = v; }
      if (col.range52 >= 0 && row[col.range52]) {
        // Parse combined range cell: "14.00 - 33.68" or "14/33.68" or "14|33.68"
        const rangeStr = String(row[col.range52]);
        const parts = rangeStr.split(/[-–\/|]/).map(p => parseFloat(p.replace(/[,$]/g,'')));
        const validParts = parts.filter(p => !isNaN(p) && p > 0);
        if (validParts.length >= 2) {
          s.week52Low  = Math.min(...validParts);
          s.week52High = Math.max(...validParts);
        }
      }
      if (col.mktcap >= 0) { const v = parseNum(row[col.mktcap]); if (v && v > 0) s.liveMarketCap = v; }
      if (col.pxchg  >= 0) { const v = parseNum(row[col.pxchg]); if (v != null)  s.livePxChange = v; }

      updateTableRow(s);

      // If this stock's card is currently open, sync all card price elements live
      if (typeof currentStock !== 'undefined' && currentStock && currentStock.ticker === resolvedKey) {
        const ccy = s.currency === 'USD' ? '$' : (s.currency + ' ');
        const livePx = s.livePrice;
        const el_price = document.getElementById('z1LivePrice');
        const el_chg   = document.getElementById('z1PriceChg');
        if (el_price) el_price.textContent = ccy + fmtPrice(livePx);
        if (el_chg) {
          const chgPct = ((livePx - s.reportPrice) / s.reportPrice * 100);
          el_chg.textContent = (chgPct >= 0 ? '+' : '') + chgPct.toFixed(1) + '% vs report';
          el_chg.style.color = chgPct >= 0 ? 'var(--green)' : 'var(--red)';
        }
        if (typeof refreshMultiples === 'function') refreshMultiples(s);
        if (typeof renderRangeBar === 'function') renderRangeBar(s);
      }

      updated++;
    }

    const now = new Date().toLocaleTimeString('en-SG', { hour: '2-digit', minute: '2-digit' });
    if (updated === 0) {
      const hintMsg = skipped.length ? ' Sheet tickers not matched: ' + skipped.slice(0,8).join(', ') : '';
      throw new Error('No matching tickers found.' + hintMsg);
    }
    const skipNote = skipped.length ? ' · ' + skipped.length + ' skipped: ' + skipped.slice(0,5).join(', ') : '';
    status.textContent = '✓ ' + updated + ' updated · ' + now + skipNote;
    status.style.color = skipped.length ? 'var(--amber)' : 'var(--green)';
    console.log('Skipped tickers (raw values from sheet):', skipped);

  } catch(e) {
    console.error('refreshAllPrices error:', e);
    status.textContent = '✗ ' + e.message.substring(0, 80);
    status.style.color = 'var(--red)';
  }

  icon.classList.remove('spin-anim');
  btn.disabled = false;
}


/* ═══════════════════════════════════════════════════
   LIVE REFRESH  (#21a, 21c, 23, 24, 25)
═══════════════════════════════════════════════════ */
async function liveRefresh() {
  if (!currentStock) return;
  const s = currentStock;

  // Skip if price unchanged <1% since last refresh
  var lastPx = s._lastRefreshPrice || 0;
  var curPx  = s.livePrice || s.reportPrice;
  if (lastPx > 0 && Math.abs((curPx - lastPx) / lastPx) < 0.01) {
    document.getElementById('updatedAdvice').innerHTML =
      '<div style="color:var(--text3);font-size:11px;padding:8px 0">Price unchanged since last refresh (&lt;1% move). Cached analysis is current. Paste updated prices first.</div>';
    return;
  }

  var btn = document.getElementById('refreshBtn');
  btn.classList.add('loading');

  s.debates.forEach(function(d) {
    var loadEl = document.getElementById(safeId(s.ticker) + '-' + d.id + '-loading');
    var contEl = document.getElementById(safeId(s.ticker) + '-' + d.id + '-content');
    if (loadEl) loadEl.style.display = 'flex';
    if (contEl) contEl.style.display = 'none';
  });
  document.getElementById('updatedAdvice').innerHTML = '<div class="updating-inline"><div class="spin-dot"></div>Running AI assessment…</div>';

  try {
    // No Call 1 - use price already set by paste box
    var px = s.livePrice || s.reportPrice;

    document.getElementById('z1LivePrice').textContent = s.currency === 'USD' ? '$' + fmtPrice(px) : s.currency + ' ' + fmtPrice(px);
    var chg = ((px - s.reportPrice) / s.reportPrice * 100);
    document.getElementById('z1PriceChg').textContent = (chg >= 0 ? '+' : '') + chg.toFixed(1) + '% vs report';
    document.getElementById('z1PriceChg').style.color = chg >= 0 ? 'var(--green)' : 'var(--red)';
    refreshMultiples(s);
    renderRangeBar(s);
    updateTableRow(s);

    // Compressed prompt - include report context if available, enable web search
    var entryGapPct = ((s.entryPrice - px) / s.entryPrice * 100);
    var priceCtx = px < s.entryPrice
      ? fmtPrice(px) + ' (' + entryGapPct.toFixed(1) + '% below entry target ' + fmtPrice(s.entryPrice) + ' - potential UPGRADE if thesis intact)'
      : fmtPrice(px) + ' (' + Math.abs(entryGapPct).toFixed(1) + '% above entry target ' + s.entryPrice + ')';

    var oilSectors = ['cruise','airline','travel','shipping','logistics','energy','transportation'];
    var oilNote = oilSectors.some(function(k) { return s.sector.toLowerCase().includes(k); })
      ? ' Brent crude elevated due to Iran tensions.' : '';

    var debateQs = s.debates.map(function(d, i) { return (i+1) + '. ' + d.question; }).join(' | ');

    // Build enriched prompt with report context
    var contextBlock = s.reportContext ? '\n--- REPORT CONTEXT (as of ' + s.reportDate + ') ---\n' + s.reportContext + '\n--- END CONTEXT ---\n' : '';

    var analysisPrompt = 'Buy-side equity analyst performing a live thesis review. Use your training knowledge of this company and sector to assess the current situation.\n\n' +
      'Stock: ' + s.ticker + ' (' + s.sector + '). Today: May 2026.\n' +
      'Live Price: ' + s.currency + ' ' + priceCtx + '. Report price: ' + s.reportPrice + '. Current rating: ' + s.rating + '.' + oilNote + '\n' +
      contextBlock +
      '\nOriginal debates: ' + debateQs + '\n\n' +
      'Return ONLY valid JSON, no markdown fences, no explanation. Schema:\n' +
      '{"thesisStatus":"INTACT|WEAKENED|STRENGTHENED|BROKEN",' +
      '"thesisReason":"one sentence with specific evidence from your search",' +
      '"keyDevelopments":["development 1 with date","development 2","development 3"],' +
      '"debate1Question":"current most important debate question (update/replace if original is stale)",' +
      '"debate1IsPrimary":true,' +
      '"debate1Status":"LIVE|RESOLVED|ESCALATED",' +
      '"debate1Verdict":"STRONGLY_BULLISH|BULL_LEANING|BEAR_LEANING|STRONGLY_BEARISH",' +
      '"debate1Update":"2-3 sentences with specific facts/numbers from search",' +
      '"debate2Question":"second debate (update/replace if stale)",' +
      '"debate2IsPrimary":false,' +
      '"debate2Status":"LIVE",' +
      '"debate2Verdict":"STRONGLY_BULLISH|BULL_LEANING|BEAR_LEANING|STRONGLY_BEARISH",' +
      '"debate2Update":"2-3 sentences",' +
      '"debate3Question":"third debate (update/replace if stale)",' +
      '"debate3IsPrimary":false,' +
      '"debate3Status":"LIVE",' +
      '"debate3Verdict":"STRONGLY_BULLISH|BULL_LEANING|BEAR_LEANING|STRONGLY_BEARISH",' +
      '"debate3Update":"2-3 sentences",' +
      '"sqScore":7,"dislocationScore":7,' +
      '"dislocationReason":"1 sentence explaining the score — reference current multiple vs history and peer multiples",' +
      '"peerMultipleUpdate":"MELI: [current P/E]x | GRAB: [current P/E]x — or N/A if not found",' +
      '"betterAltUpdate":"MELI still premium at Xx vs SE Xx — SE remains deeper value OR [peer] now cheaper at Xx",' +
      '"actionChange":"UNCHANGED|UPGRADE|DOWNGRADE",' +
      '"actionReason":"one sentence",' +
      '"immediateAction":"one specific action instruction",' +
      '"keyWatchItem":"most important event in next 30 days with date",' +
      '"riskAlert":"biggest NEW risk since report or NONE",' +
      '"netSentiment":"BULLISH|MILDLY_BULLISH|NEUTRAL|MILDLY_BEARISH|BEARISH",' +
      '"netSentimentText":"one sentence","capitalAllocationUpdate":"2-3 sentences updating position sizing and action based on current price vs entry and thesis strength"}\n\n' +
      'Rules: (1) Use web search to find RECENT news, earnings, analyst updates, and macro events for this stock. Search for "[TICKER] earnings 2026", "[TICKER] stock news May 2026". (2) keyDevelopments: list 2-3 SPECIFIC things with dates that have happened since the report date — be concrete, not generic. (3) If an original debate is now resolved or stale, replace with a new active debate — keep exactly 3 debates total. (4) Mark the single most important debate isPrimary:true. (5) sqScore: re-assess structural quality 1-10 based on any changes to moat, returns profile, competitive position, or management execution since the report. Only change if there is real evidence. (6) dislocationScore: assess qualitatively 1-10 based on CURRENT valuation vs historical range and peers — look up current multiples. (7) immediateAction and keyWatchItem should be SPECIFIC and ACTIONABLE with real dates. (8) capitalAllocationUpdate: write 2-3 sentences updating the position sizing / action recommendation based on current price vs entry price and thesis strength.';

    var analysisRaw = await callClaude(analysisPrompt, true);
    // Strip any citation markup from web search responses
    analysisRaw = analysisRaw.replace(/<\/?cite[^>]*>/g, '').replace(/<\/?antml:[^>]*>/g, '');
    var analysis = null;
    try {
      // Strip markdown fences and whitespace
      var clean2 = analysisRaw.replace(/```json\s*/gi, '').replace(/```\s*/g, '').trim();
      // Find the JSON object boundaries
      var s2 = clean2.indexOf('{'), e2 = clean2.lastIndexOf('}');
      if (s2 !== -1 && e2 !== -1 && e2 > s2) {
        var jsonStr = clean2.substring(s2, e2 + 1);
        try {
          analysis = JSON.parse(jsonStr);
        } catch(pe) {
          // Try to repair truncated JSON by closing open strings/objects
          var repaired = jsonStr;
          // Count unmatched braces
          var openBraces = (repaired.match(/{/g) || []).length;
          var closeBraces = (repaired.match(/}/g) || []).length;
          var openBrackets = (repaired.match(/\[/g) || []).length;
          var closeBrackets = (repaired.match(/]/g) || []).length;
          // Close any open string
          var quoteCount = (repaired.match(/"/g) || []).length;
          if (quoteCount % 2 !== 0) repaired += '"';
          // Close open arrays
          for (var qi = 0; qi < openBrackets - closeBrackets; qi++) repaired += ']';
          // Close open objects
          for (var qi = 0; qi < openBraces - closeBraces; qi++) repaired += '}';
          try {
            analysis = JSON.parse(repaired);
            console.log('JSON repaired successfully after truncation');
          } catch(pe2) {
            console.warn('JSON repair failed, trying substring extraction');
            // Last resort: extract whatever fields we can from the truncated JSON
            var partialFields = {};
            var fieldPatterns = [
              /\"thesisStatus\"\s*:\s*\"([^\"]+)\"/,
              /\"thesisReason\"\s*:\s*\"([^\"]+)\"/,
              /\"actionChange\"\s*:\s*\"([^\"]+)\"/,
              /\"actionReason\"\s*:\s*\"([^\"]+)\"/,
              /\"netSentiment\"\s*:\s*\"([^\"]+)\"/,
              /\"dislocationScore\"\s*:\s*(\d+)/,
              /\"dislocationReason\"\s*:\s*\"([^\"]+)\"/,
              /\"debate1Verdict\"\s*:\s*\"([^\"]+)\"/,
              /\"debate2Verdict\"\s*:\s*\"([^\"]+)\"/,
              /\"debate3Verdict\"\s*:\s*\"([^\"]+)\"/,
              /\"immediateAction\"\s*:\s*\"([^\"]+)\"/,
              /\"keyWatchItem\"\s*:\s*\"([^\"]+)\"/,
            ];
            var fieldNames = ['thesisStatus','thesisReason','actionChange','actionReason','netSentiment','dislocationScore','dislocationReason','debate1Verdict','debate2Verdict','debate3Verdict','immediateAction','keyWatchItem'];
            fieldPatterns.forEach(function(pat, idx) {
              var m = jsonStr.match(pat);
              if (m) partialFields[fieldNames[idx]] = idx === 5 ? parseInt(m[1]) : m[1];
            });
            // Extract keyDevelopments array
            var devMatch = jsonStr.match(/\"keyDevelopments\"\s*:\s*\[([^\]]*)\]/);
            if (devMatch) {
              try { partialFields.keyDevelopments = JSON.parse('[' + devMatch[1] + ']'); } catch(x) {}
            }
            if (Object.keys(partialFields).length >= 3) {
              analysis = partialFields;
              console.log('Extracted ' + Object.keys(partialFields).length + ' fields from truncated JSON');
            }
          }
        }
      }
    } catch(e) { console.warn('Analysis parse failed:', e.message, analysisRaw.substring(0, 200)); }

    if (analysis) {
      var banner = document.getElementById('thesisBanner');
      var icons = { INTACT:'\u2713 THESIS INTACT', WEAKENED:'\u26a0 THESIS WEAKENED', STRENGTHENED:'\u2191 THESIS STRENGTHENED', BROKEN:'\u2717 THESIS BROKEN' };
      banner.className = 'thesis-banner ' + (analysis.thesisStatus || 'INTACT');
      banner.textContent = (icons[analysis.thesisStatus] || '\u2713') + ' \u2014 ' + (analysis.thesisReason || '');
      s._cachedThesisBanner = { cls: banner.className, text: banner.textContent };

      // Update debate questions if AI provided new ones (replacing stale debates)
      s.debates.forEach(function(d, i) {
        var n = i + 1;
        var newQ = analysis['debate' + n + 'Question'];
        if (newQ && newQ.length > 10) d.question = newQ;  // Replace stale question
        var status  = analysis['debate' + n + 'Status']  || 'LIVE';
        var verdict = analysis['debate' + n + 'Verdict'] || 'NEUTRAL';
        var update  = analysis['debate' + n + 'Update']  || 'No update available.';
        var isPrimary = analysis['debate' + n + 'IsPrimary'] || false;
        var statusEl = document.getElementById(safeId(s.ticker) + '-' + d.id + '-status');
        var loadEl   = document.getElementById(safeId(s.ticker) + '-' + d.id + '-loading');
        var contEl   = document.getElementById(safeId(s.ticker) + '-' + d.id + '-content');
        if (!s._cachedDebateUpdates) s._cachedDebateUpdates = {};
        s._cachedDebateUpdates[d.id] = { status: status, verdict: verdict, update: update, isPrimary: isPrimary, question: d.question };
        if (statusEl) { statusEl.textContent = (isPrimary ? '★ ' : '') + status; statusEl.className = 'debate-status ' + status; }
        if (loadEl) loadEl.style.display = 'none';
        if (contEl) {
          var vEl = document.getElementById(s.ticker + '-' + d.id + '-verdict');
          var verdictLabel = verdict === 'STRONGLY_BULLISH' ? '\u25b2\u25b2 Strongly Bull' : verdict === 'BULL_LEANING' ? '\u25b2 Bull Leaning' : verdict === 'BEAR_LEANING' ? '\u25bc Bear Leaning' : verdict === 'STRONGLY_BEARISH' ? '\u25bc\u25bc Strongly Bear' : verdict === 'BULL_WINNING' ? '\u25b2 Bull Winning' : verdict === 'BEAR_WINNING' ? '\u25bc Bear Winning' : '\u25c6 Neutral';
          if (vEl) { vEl.textContent = verdictLabel; vEl.className = 'debate-verdict-label ' + (['STRONGLY_BULLISH','BULL_LEANING','BULL_WINNING'].indexOf(verdict) >= 0 ? 'bull' : ['STRONGLY_BEARISH','BEAR_LEANING','BEAR_WINNING'].indexOf(verdict) >= 0 ? 'bear' : 'neutral'); }
          // Update the debate title if question changed
          var titleEl = document.querySelector('#' + safeId(s.ticker) + '-' + d.id + '-content').closest('.debate-card');
          if (titleEl && newQ) {
            var titleSpan = titleEl.querySelector('.debate-title span[style]');
            if (titleSpan) titleSpan.textContent = d.question;
          }
          contEl.textContent = update;
          contEl.style.display = 'block';
        }
      });

      // Re-render debates to pick up new questions and primary markers
      renderDebates(s);

      var actionColor = analysis.actionChange === 'UPGRADE' ? 'var(--green)' : analysis.actionChange === 'DOWNGRADE' ? 'var(--red)' : 'var(--text3)';
      var actionIcon  = analysis.actionChange === 'UPGRADE' ? '\u2191' : analysis.actionChange === 'DOWNGRADE' ? '\u2193' : '\u2192';
      var riskHtml = analysis.riskAlert && analysis.riskAlert !== 'NONE'
        ? '<div style="margin-top:8px;padding:8px 10px;background:var(--red-bg);border:1px solid var(--red-bd);border-radius:5px;border-left:3px solid var(--red)"><div style="font-size:8px;font-weight:700;letter-spacing:.1em;color:var(--red);text-transform:uppercase;margin-bottom:3px">\u26a0 Risk Alert</div><div style="font-size:11px;color:var(--text2);line-height:1.4">' + analysis.riskAlert + '</div></div>' : '';

      // Key developments block
      var devHtml = '';
      if (analysis.keyDevelopments && analysis.keyDevelopments.length) {
        devHtml = '<div style="padding:8px 10px;background:var(--bg);border:1px solid var(--border2);border-radius:5px;border-left:3px solid var(--cyan)">' +
          '<div style="font-size:8px;font-weight:700;letter-spacing:.1em;color:var(--cyan);text-transform:uppercase;margin-bottom:4px">What\'s Changed Since Report</div>' +
          analysis.keyDevelopments.map(function(d) { return '<div style="font-size:10px;color:var(--text2);line-height:1.4;padding-left:10px;position:relative;margin-bottom:2px"><span style="position:absolute;left:0;color:var(--cyan)">•</span>' + d + '</div>'; }).join('') +
          '</div>';
      }

      // Peer multiple update
      var peerHtml = '';
      if (analysis.peerMultipleUpdate) {
        peerHtml = '<div style="font-size:9px;color:var(--text3);margin-top:4px;font-family:DM Mono,monospace">Peers: ' + analysis.peerMultipleUpdate + '</div>';
      }

      // Better alternative update  
      var altHtml = '';
      if (analysis.betterAltUpdate) {
        altHtml = '<div style="margin-top:4px;font-size:9px;color:var(--text2);font-style:italic">' + analysis.betterAltUpdate + '</div>';
      }

      // Build debate mini-cards for the updated panel
      var debateMiniCards = s.debates.map(function(d,i) {
        var n = i+1;
        var verdict = analysis['debate'+n+'Verdict'] || 'NEUTRAL';
        var vc = ['STRONGLY_BULLISH','BULL_LEANING','BULL_WINNING'].indexOf(verdict) >= 0 ? 'var(--green)' : ['STRONGLY_BEARISH','BEAR_LEANING','BEAR_WINNING'].indexOf(verdict) >= 0 ? 'var(--red)' : 'var(--amber)';
        var vl = verdict === 'STRONGLY_BULLISH' ? '\u25b2\u25b2 Strong Bull' : verdict === 'BULL_LEANING' ? '\u25b2 Bull Lean' : verdict === 'STRONGLY_BEARISH' ? '\u25bc\u25bc Strong Bear' : verdict === 'BEAR_LEANING' ? '\u25bc Bear Lean' : verdict === 'BULL_WINNING' ? '\u25b2 Bull' : verdict === 'BEAR_WINNING' ? '\u25bc Bear' : '\u25c6 Neutral';
        var st = analysis['debate'+n+'Status'] || 'LIVE';
        var isPrimary = analysis['debate'+n+'IsPrimary'] || false;
        var qText = analysis['debate'+n+'Question'] || d.question;
        return '<div style="padding:7px 10px;background:var(--bg);border:1px solid var(--border2);border-radius:5px' + (isPrimary ? ';border-left:3px solid var(--gold)' : '') + '">' +
          '<div style="font-size:8px;font-weight:700;letter-spacing:.08em;color:var(--text3);text-transform:uppercase;margin-bottom:3px">' + (isPrimary ? '★ ' : '') + 'Debate ' + n + '</div>' +
          '<div style="font-size:10px;color:var(--text2);margin-bottom:4px;line-height:1.3">' + qText.substring(0,65) + '\u2026</div>' +
          '<span style="font-size:9px;font-weight:700;color:' + vc + '">' + vl + '</span>' +
          '<span style="font-size:8px;color:var(--text3);margin-left:6px">' + st + '</span></div>';
      }).join('');

      document.getElementById('updatedAdvice').innerHTML =
        '<div style="display:flex;flex-direction:column;gap:8px">' +
        devHtml +
        '<div style="display:flex;align-items:center;gap:10px;flex-wrap:wrap">' +
          '<span style="font-size:9px;font-weight:700;letter-spacing:.1em;color:var(--text3);text-transform:uppercase">Recommendation</span>' +
          '<span style="font-family:\'DM Mono\',monospace;font-size:12px;font-weight:600;color:' + actionColor + '">' + actionIcon + ' ' + (analysis.actionChange || 'UNCHANGED') + '</span>' +
          '<span style="font-size:11px;color:var(--text2);flex:1">' + (analysis.actionReason || '') + '</span>' +
        '</div>' +
        '<div style="display:grid;grid-template-columns:1fr 1fr;gap:8px">' +
          '<div style="padding:8px 10px;background:var(--s3);border:1px solid var(--border2);border-radius:5px;border-left:3px solid var(--blue)">' +
            '<div style="font-size:8px;font-weight:700;letter-spacing:.1em;color:var(--blue);text-transform:uppercase;margin-bottom:4px">\u25b6 Immediate Action</div>' +
            '<div style="font-size:10px;color:var(--text2);line-height:1.4">' + (analysis.immediateAction || '\u2014') + '</div></div>' +
          '<div style="padding:8px 10px;background:var(--s3);border:1px solid var(--border2);border-radius:5px;border-left:3px solid var(--gold)">' +
            '<div style="font-size:8px;font-weight:700;letter-spacing:.1em;color:var(--gold);text-transform:uppercase;margin-bottom:4px">\u25b6 Watch in 30 Days</div>' +
            '<div style="font-size:10px;color:var(--text2);line-height:1.4">' + (analysis.keyWatchItem || '\u2014') + '</div></div>' +
        '</div>' +
        '<div style="display:grid;grid-template-columns:repeat(3,1fr);gap:6px">' + debateMiniCards + '</div>' +
        peerHtml + altHtml +
        (analysis.capitalAllocationUpdate ? '<div style="margin-top:6px;padding:9px 12px;background:var(--s2);border:1px solid var(--border2);border-radius:5px;border-left:3px solid var(--gold)"><div style="font-size:8px;font-weight:700;letter-spacing:.1em;color:var(--gold);text-transform:uppercase;margin-bottom:3px">▶ Updated Capital Allocation</div><div style="font-size:11px;color:var(--text2);line-height:1.6">' + analysis.capitalAllocationUpdate + '</div></div>' : '') +
        riskHtml + '</div>';

      var _ad = new Date();
      var _amonths = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
      var assessTime = 'AI · ' + _amonths[_ad.getMonth()] + ' ' + _ad.getDate() + ', ' + _ad.getFullYear();
      document.getElementById('assessmentTime').textContent = assessTime;
      s._cachedAssessmentTime = assessTime;
      s._cachedAdviceHTML = document.getElementById('updatedAdvice').innerHTML;

      if (analysis.netSentiment) {
        var nb = document.getElementById('netSentimentBadge');
        nb.className = 'net-sentiment-badge ' + analysis.netSentiment;
        nb.textContent = analysis.netSentiment.replace(/_/g, ' ');
        s.netSentiment = analysis.netSentiment;
      }
      if (analysis.netSentimentText) document.getElementById('netSentimentText').textContent = analysis.netSentimentText;

      var upsidePct = ((s.targetPrice - px) / px * 100);
      // Use AI-driven dislocation score if available, else fall back to mechanical
      // Apply AI-assessed SQ score if returned
      if (analysis.sqScore && analysis.sqScore >= 1 && analysis.sqScore <= 10) {
        s.sqScore = analysis.sqScore;
      }
      var newDislocation = analysis.dislocationScore || s.dislocationScore || s.dislocationAtReport;
      if (typeof newDislocation !== 'number' || newDislocation < 1 || newDislocation > 10) {
        // Fallback mechanical calculation
        newDislocation = upsidePct > 50 ? 9 : upsidePct > 40 ? 8 : upsidePct > 28 ? 7 : upsidePct > 18 ? 6 : upsidePct > 8 ? 5 : 4;
      }
      s.dislocationScore = newDislocation;
      var dislocationReason = analysis.dislocationReason || '';
      document.getElementById('cardDislocation').innerHTML = newDislocation + ' <span style="font-size:11px;color:var(--text3)">(' + s.dislocationAtReport + ')</span>';
      document.getElementById('cardDislocation').style.color = sqColor(newDislocation);
      // Update SQ score display in card header
      var sqEl = document.getElementById('cardSQ');
      if (sqEl) { sqEl.textContent = s.sqScore; sqEl.style.color = sqColor(s.sqScore); }
      {
        var sqPillEl = document.querySelector('#watchlistBody tr[data-ticker="' + s.ticker + '"] .sq-pill');
        if (sqPillEl) sqPillEl.innerHTML = '<span class="sq-dot" style="background:' + sqColor(s.sqScore) + '"></span>' + s.sqScore + '/' + newDislocation;
      }

      if (analysis.actionChange === 'UPGRADE' || analysis.actionChange === 'DOWNGRADE') {
        var ratingMap = { UPGRADE: { WAIT:'BUY', HOLD:'BUY', SELL:'HOLD' }, DOWNGRADE: { BUY:'HOLD', HOLD:'WAIT', WAIT:'SELL' } };
        var newRatingLive = (ratingMap[analysis.actionChange] || {})[s.rating] || s.rating;
        var pfx = analysis.actionChange === 'UPGRADE' ? '\u2191 ' : '\u2193 ';
        var liveBadge = document.getElementById('cardActionBadge');
        liveBadge.textContent = pfx + newRatingLive;
        liveBadge.className = 'action-badge ' + newRatingLive;
        s._cachedActionBadge = { text: liveBadge.textContent, cls: liveBadge.className };
        // Update card shell border color
        document.getElementById('cardShell').className = 'card-shell ' + newRatingLive;
      }
      if (analysis.immediateAction) {
        document.getElementById('cardInstruction').textContent = analysis.immediateAction;
        s._cachedInstruction = analysis.immediateAction;
      }
      if (analysis.keyWatchItem) {
        document.getElementById('cardTrigger').textContent = analysis.keyWatchItem;
        s._cachedTrigger = analysis.keyWatchItem;
      }

      // Sync capital guidance box (zone4-orig) if action changed
      if (analysis.actionChange === 'UPGRADE' || analysis.actionChange === 'DOWNGRADE') {
        var capRecEl = document.getElementById('capOrigRec');
        var newRatingForCap = (({'UPGRADE':{WAIT:'BUY',HOLD:'BUY',SELL:'HOLD'},'DOWNGRADE':{BUY:'HOLD',HOLD:'WAIT',WAIT:'SELL'}}[analysis.actionChange])||{})[s.rating] || s.rating;
        if (capRecEl) capRecEl.className = 'cap-final-rec ' + newRatingForCap;
        s._cachedCapRating = newRatingForCap;
        // Update table row left border colour
        var trEl = document.querySelector('#watchlistBody tr[data-ticker="' + s.ticker + '"]');
        if (trEl) trEl.className = newRatingForCap;
      }

      // Re-render Score Breakdown section with latest data
      if (dislocationReason && s.dislocationExplain && s.dislocationExplain.length) {
        s.dislocationExplain[0] = { factor: 'Live Assessment', detail: dislocationReason, sentiment: s.dislocationScore >= 7 ? 'positive' : s.dislocationScore >= 5 ? 'neutral' : 'negative' };
      }
      // Update score numbers directly (always works even if renderScoreExplain fails)
      var sqInline = document.getElementById('z1SQScoreInline');
      var disInline = document.getElementById('z1DisScoreInline');
      if (sqInline) { sqInline.textContent = s.sqScore + '/10'; sqInline.style.color = sqColor(s.sqScore); }
      if (disInline) { disInline.textContent = s.dislocationScore + '/10'; disInline.style.color = sqColor(s.dislocationScore); }
      // Re-render the explain grids
      try {
        if (typeof renderScoreExplain === 'function') {
          renderScoreExplain('z1SQExplain', s.sqExplain, s.sqScore, 'z1SQScoreInline');
          renderScoreExplain('z1DisExplain', s.dislocationExplain, s.dislocationScore, 'z1DisScoreInline');
        }
      } catch(scoreErr) { console.warn('Score explain render:', scoreErr.message); }

      s._lastRefreshPrice = px;

    } else {
      document.getElementById('updatedAdvice').innerHTML = '<div style="color:var(--text3);font-size:11px">Parse failed. Raw: ' + analysisRaw.substring(0, 300) + '</div>';
      s.debates.forEach(function(d) {
        var loadEl = document.getElementById(s.ticker + '-' + d.id + '-loading');
        var contEl = document.getElementById(s.ticker + '-' + d.id + '-content');
        if (loadEl) loadEl.style.display = 'none';
        if (contEl) { contEl.textContent = 'See updated advice panel.'; contEl.style.display = 'block'; }
      });
    }

  } catch(err) {
    console.error('Refresh error:', err);
    var isNetworkErr = err.message.includes('Failed to fetch') || err.message.includes('NetworkError') || err.message.includes('net::');
    var errMsg = isNetworkErr
      ? '<div style="padding:10px 12px;background:var(--s2);border:1px solid var(--border2);border-radius:6px;border-left:3px solid var(--amber)">' +
        '<div style="font-size:9px;font-weight:700;letter-spacing:.1em;color:var(--amber);text-transform:uppercase;margin-bottom:4px">⚠ Offline Mode</div>' +
        '<div style="font-size:11px;color:var(--text2);line-height:1.5">Live AI analysis requires the claude.ai session for API access. ' +
        'The cached analysis above is your last saved assessment. ' +
        'Open this file from within <strong>claude.ai</strong> to run a live refresh.</div></div>'
      : '<div style="color:var(--red);font-size:11px;padding:8px">Refresh error: ' + err.message + '</div>';
    document.getElementById('updatedAdvice').innerHTML = errMsg;
  }

  var _now = new Date();
  var _dayNames = ['Sun','Mon','Tue','Wed','Thu','Fri','Sat'];
  var _monthNames = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
  var _today = new Date(); _today.setHours(0,0,0,0);
  var _reportDt = new Date(currentStock ? currentStock.reportDate : _now);
  _reportDt.setHours(0,0,0,0);
  var _daysAgo = Math.floor((_today - _reportDt) / 86400000);
  var _dateStr = _monthNames[_now.getMonth()] + ' ' + _now.getDate() + ', ' + _now.getFullYear();
  var _daysLabel = _daysAgo === 0 ? 'today' : _daysAgo === 1 ? '1 day ago' : _daysAgo + ' days ago';
  var refreshedStr = 'Refreshed ' + _dateStr + ' · memo ' + _daysLabel;
  document.getElementById('lastRefreshed').textContent = refreshedStr;
  if (currentStock) {
    currentStock._cachedLastRefreshed = refreshedStr;
    // Sync landing page table row with all refreshed data
    updateTableRow(currentStock);
  }
  btn.classList.remove('loading');
}

/* ═══════════════════════════════════════════════════
   CLAUDE API CALL
═══════════════════════════════════════════════════ */
async function callClaude(prompt, useSearch = false) {
  const HEADERS = { 'Content-Type': 'application/json' };
  const BASE = {
    model: 'claude-sonnet-4-6',
    max_tokens: 3000,
    system: 'You are a financial data assistant. Always respond with only valid JSON when asked for JSON. Never include markdown code blocks, explanations, or any text outside the JSON object.',
  };
  const tools = useSearch ? [{ type: 'web_search_20250305', name: 'web_search', max_uses: 1 }] : [];

  let messages = [{ role: 'user', content: prompt }];

  // Call Anthropic API directly — works from claude.ai artifacts (session handles auth).
  // For standalone use, an API key would be needed; feature degrades gracefully.
  const CLAUDE_ENDPOINT = 'https://api.anthropic.com/v1/messages';

  // Agentic loop: keep going until we get a final text response (stop_reason = 'end_turn')
  // Limited to 3 iterations to control token cost (~$0.03 per refresh with 1 web search)
  for (let i = 0; i < 3; i++) {
    const body = { ...BASE, messages };
    if (tools.length) body.tools = tools;

    const res = await fetch(CLAUDE_ENDPOINT, {
      method: 'POST',
      headers: HEADERS,
      body: JSON.stringify(body)
    });
    if (!res.ok) {
      const err = await res.text();
      throw new Error('API ' + res.status + ': ' + err.substring(0, 200));
    }
    const data = await res.json();
    const content = data.content || [];

    // Append assistant turn to messages
    messages.push({ role: 'assistant', content });

    // If stop_reason is end_turn, return the last text block
    if (data.stop_reason === 'end_turn') {
      const textBlocks = content.filter(b => b.type === 'text');
      if (!textBlocks.length) throw new Error('No text in final response');
      return textBlocks[textBlocks.length - 1].text;
    }

    // If stop_reason is tool_use, build proper tool_result responses
    if (data.stop_reason === 'tool_use') {
      const toolUseBlocks = content.filter(b => b.type === 'tool_use');
      if (!toolUseBlocks.length) throw new Error('stop_reason=tool_use but no tool_use blocks');

      // For web_search, the API executes the search internally and expects us to send
      // a user turn with tool_result blocks — the search results are embedded in the
      // assistant's content as server_tool_use / mcp_tool_result blocks automatically.
      // We just need to acknowledge each tool_use with an empty tool_result so the
      // model can continue with the search results it already has.
      const toolResults = toolUseBlocks.map(tu => ({
        type: 'tool_result',
        tool_use_id: tu.id,
        content: tu.input ? JSON.stringify(tu.input) : '{}',
      }));
      messages.push({ role: 'user', content: toolResults });
      continue;
    }

    // Any other stop reason — try to extract text
    const textBlocks = content.filter(b => b.type === 'text');
    if (textBlocks.length) return textBlocks[textBlocks.length - 1].text;
    throw new Error('Unexpected stop_reason: ' + data.stop_reason);
  }
  throw new Error('Max iterations reached in callClaude');
}


